INSERT INTO content
                    VALUES (153, '<p style="text-align: center;"><img src="http://127.0.0.1:3400/data/upload/editor/1750296098549.png" alt="1750296098549.png" data-href="/data/upload/editor/1750296098549.png" style="width: 840.98px;height: 1190.18px;"></p>');
INSERT INTO content
                    VALUES (154, '<p style="text-align: center;"><br></p><p style="text-align: center;"><br></p><p style="text-align: center;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-size: 24px;">IBM大楼三楼教务处</span></p>');
INSERT INTO content
                    VALUES (155, '<p style="text-align: start;">联系电话：0791-83792933</p><p style="text-align: start;">邮 &nbsp; &nbsp; &nbsp; 箱：jrjwc_123@163.com</p>');
INSERT INTO content
                    VALUES (156, '<p><img src="/data/upload/editor/1750296274884.png" alt="1750296274884.png" data-href="/data/upload/editor/1750296274884.png" style="width: 100%;"/></p>');
INSERT INTO content
                    VALUES (157, '<p> <a href="http://jwc.jxuspt.edu.cn/resource_znkj/20250109/677f7f1cb760ba23a2900af0.pdf" target="_blank">1.关于印发《江西软件职业技术大学课程考核工作规程（2024修订）》的通知</a> </p><p> <a href="http://jwc.jxuspt.edu.cn/resource_znkj/20250105/677a2599b760ba23a2900aef.zip" target="_blank">2.江西软件职业技术大学课程考核工作规程及考试相关附件</a> </p>');
INSERT INTO content
                    VALUES (158, '<p style="text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院：</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">按照人才培养方案，2025届毕业班学生即将开始专业实训和岗位实习。为切实加强教学管理，保证教学效果，现将2025届毕业班学生专业实训和岗位实习工作安排有关事项通知如下：</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>一、教学进程安排</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">2025届毕业班专业实训和岗位实习安排在2024-2025学年，分两学期进行，原则上总时间不少于26周。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>1.2024-2025学年第一学期。</strong></span><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">2025届毕业班将要完成的教学任务为：《大学生职业生涯规划与就业指导》等少部分尚未结束的课程教学，专业实训。教学安排如下：</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">（1）前8周完成部分课程教学、专业实训、毕业设计（论文）选题开题等工作。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">（2）后8周进行岗位实习、撰写毕业设计（论文）。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>2.2024-2025学年第二学期。</strong></span><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">2025届毕业班主要进行岗位实习，完成毕业设计（论文）。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>二、高度重视，制定专业实训和岗位实习工作计划</strong></span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>1.成立专业实训和岗位实习教学工作领导小组</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要高度重视专业实训和岗位实习教学工作，要成立以院长为组长的专业实训和岗位实习教学工作领导小组，统筹领导和部署专业实训和岗位实习教学工作，可分专业设定教学工作小组，由组长负责组织该专业的专业实训和岗位实习教学具体工作。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>2.制定好专业实训和岗位实习工作计划</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要分专业制定切实可行的专业实训和岗位实习工作计划，</span><span style="font-size: 14px;"><strong>内容应包括：组织领导、目的和要求、形式和内容、时间和场所、指导教师安排、过程质量监控、主要实践环节、纪律与注意事项等</strong></span><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">。 &nbsp; &nbsp;</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">工作计划要坚持理论联系实际，提高针对性和实效性。专业实训工作计划于9月10日前送教务处实践教学科备案，岗位实习工作计划于9月20日前送教务处实践教学科备案。</span><span style="font-size: 14px;"><strong>联系人：李秋霞，18179109398。</strong></span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>三、加强岗位实习工作组织和管理</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">为了确保岗位实习工作落到实处，在完成前期准备工作的基础上，特作如下要求：</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>1.摸清底数，打好基础</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">为了做到“家底清、底数明”，各学院须对目前合作的校外实习（实践）基地进行逐一联系，建立《校外实习（实践）基地台账》，摸清实习（实践）基地可接纳学生人数、岗位、实习时间安排等基础信息，为2025届毕业班学生顺利完成岗位实习工作打下坚实基础。各学院于9月10日前将《校外实习（实践）基地台账》（见附件1）报送教务处实践教学科。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>2.开好实习前的动员培训会</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要分专业制定岗位实习计划。实习前各学院要召开毕业实习动员培训大会，使实习学生明确实习目的、内容、安全、成绩评定等相关事宜，明确岗位实习纪律和指导教师的职责。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要强调实习纪律，强化实习期间的安全教育，各班召开实习安全教育主题班会，确保实习生接受安全教育培训全覆盖。签订《江西软件职业技术大学学生实习安全协议书》，明确实习安全责任，防止实习期间意外事故的发生。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>3.合理安排，组织落实好岗位实习工作</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要根据专业实际情况不断探索岗位实习组织模式，采取集中与自主、校内与校外、实习与就业（创业）、实习与毕业设计（论文）相结合等多种形式组织毕业实践教学。各学院要尽可能安排学生在已签订协议的实习基地集中实习。学生自主联系实习单位应与所学专业相关，须先履行申请手续，填写《江西软件职业技术大学学生自主联系实习单位申请表》，经实习单位同意接收实习后，所在学院审批同意，进行登记备案，不得放任自流。。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">在实习过程中，要努力把实习与承担实习单位的实际工作任务结合起来，既使学生受到实践锻炼，又为实习单位做出贡献，以取得实习单位的支持。同时各学院要充分利用社会资源，积极拓展新的校外实习实训基地，加强校企合作，保证实习场所和实习任务的落实，并积极推进产学研合作教育。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>4.加强对岗位实习工作的指导与检查</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院要按照学校关于岗位实习工作的有关规定，加强学生实习的规范化管理。实习前要做好实习指导教师的选配工作。实习期间，指导教师对实习工作全面负责。指导教师应按岗位实习计划和工作职责要求，做好现场指导或定期通过电话、网络等方式与学生保持联系，指导和督促学生按时完成实习各项工作和实习日记、月度小结、实习报告的撰写等。无论采取何种指导方式，指导教师均应作好实习指导联系记录，完成指导实习任务。各专业班级辅导员要协同配合做好学生实习期间的思想政治工作，时刻关注实习学生的身心健康和安全。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院也应加强与实习单位的密切联系，指派专人不定期到校外各实习点进行检查和调研，及时掌握学生实习动态，加强对学生实习和教师指导工作的督查，及时研究处理实习过程中出现的问题，保证实习顺利进行。</span></p><p style="text-indent: 29.7pt; text-align: justify;"><span style="font-size: 14px;"><strong>5.认真做好实习总结及材料归档工作</strong></span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">学生按计划完成实习工作后，指导教师应依据学生实习月度小结、实习报告和实习单位的鉴定意见等过程材料对学生在整个岗位实习期间的思想、工作表现、工作成效和收获等方面进行综合考核，做出成绩评定和评语，并提交《岗位实习成绩汇总表》至教务处实践教学科。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">岗位实习结束后，各学院应认真做好毕业实习的总结和评估工作，其主要内容包括：实习计划执行情况、学生实习表现、教师指导工作情况、实习质量、学生总体水平分析、存在的问题及改进措施等，学生岗位实习材料由各学院收集整理并归档保管。（岗位实习材料清单见附件2）</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院实习总结和评估材料报教务处实践教学科备案，质量检测与评估中心将组织人员对岗位实习实施过程进行检查，对岗位实习实施情况进行质量评估，评估结果将作为实践教学环节量化考核的依据。</span></p><p style="text-indent: 29.6pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;">加强实践教学工作，是实现高素质高层次技术技能人才培养目标的有效途径和重要保证，也是经济社会发展对人才培养提出的客观要求。此项工作的安排时间紧、任务重、难度大，请各学院要高度重视、积极创造实践教学的良好环境和条件，切实加强实施过程的质量监控管理，不断探索实践教学管理新机制，努力促使本次实践教学工作落到实处，顺利实施，达到预期效果。</span></p><p style="text-indent: 29.6pt; text-align: justify;"> </p><p style="text-indent: 29.6pt; text-align: justify;"> </p><p style="text-indent: 24pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;"> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;江西软件职业技术大学教务处</span></p><p style="text-indent: 24pt; text-align: justify;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;"> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2024年9月5日</span></p><p style="text-align: start;"><span style="font-family: 宋体;"> </span></p><p style="text-align: start;"><br></p><p style="text-align: justify;"><span style="font-size: 14px;"><strong>附件1</strong></span></p><p style="text-align: center;"><span style="font-size: 14px;"><strong>校外实习（实践）基地台账</strong></span></p><table style="width: auto; text-align: justify;"><tbody><tr><td colspan="1" rowspan="1" width="68">序号</td><td colspan="1" rowspan="1" width="123">学院</td><td colspan="1" rowspan="1" width="181">专业</td><td colspan="1" rowspan="1" width="267">实习基地</td><td colspan="1" rowspan="1" width="80">可接纳学生数</td><td colspan="1" rowspan="1" width="95">岗位</td><td colspan="1" rowspan="1" width="122">时间安排</td></tr><tr><td colspan="1" rowspan="1" width="68"></td><td colspan="1" rowspan="1" width="123"></td><td colspan="1" rowspan="1" width="181"></td><td colspan="1" rowspan="1" width="267"></td><td colspan="1" rowspan="1" width="80"></td><td colspan="1" rowspan="1" width="95"></td><td colspan="1" rowspan="1" width="122"></td></tr><tr><td colspan="1" rowspan="1" width="68"></td><td colspan="1" rowspan="1" width="123"></td><td colspan="1" rowspan="1" width="181"></td><td colspan="1" rowspan="1" width="267"></td><td colspan="1" rowspan="1" width="80"></td><td colspan="1" rowspan="1" width="95"></td><td colspan="1" rowspan="1" width="122"></td></tr><tr><td colspan="1" rowspan="1" width="68"></td><td colspan="1" rowspan="1" width="123"></td><td colspan="1" rowspan="1" width="181"></td><td colspan="1" rowspan="1" width="267"></td><td colspan="1" rowspan="1" width="80"></td><td colspan="1" rowspan="1" width="95"></td><td colspan="1" rowspan="1" width="122"></td></tr><tr><td colspan="1" rowspan="1" width="68"></td><td colspan="1" rowspan="1" width="123"></td><td colspan="1" rowspan="1" width="181"></td><td colspan="1" rowspan="1" width="267"></td><td colspan="1" rowspan=