dth="68"></td><td colspan="1" rowspan="1" width="123"></td><td colspan="1" rowspan="1" width="181"></td><td colspan="1" rowspan="1" width="267"></td><td colspan="1" rowspan="1" width="80"></td><td colspan="1" rowspan="1" width="95"></td><td colspan="1" rowspan="1" width="122"></td></tr></tbody></table><p style="text-align: start;"><span style="color: rgb(51, 51, 51); background-color: rgb(255, 255, 255); font-family: 宋体;"> </span></p><p style="text-align: justify;"><span style="font-size: 14px;"><strong>附件2</strong></span></p><p style="text-align: center;"><span style="font-size: 24px;"><strong>岗位实习材料清单</strong></span></p><p style="text-align: center;"> </p><p style="text-align: center;"> </p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">1.江西软件职业技术大学学生实习安全协议书 </span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">2.江西软件职业技术大学集中实习校企安全协议书</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">3.江西软件职业技术大学学生自主联系实习单位申请表</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">4.职业学校学生岗位实习三方协议</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">5.**学院**专业岗位实习计划安排表</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">6.**学院**专业岗位实习月度小结</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">7.**学院**专业岗位实习报告</span></p><p style="text-align: start;"><span style="color: rgb(0, 0, 0);">8.江西软件职业技术大学实习鉴定与成绩评定表</span></p><p><span style="color: rgb(0, 0, 0);">9.**学院**专业**班学生岗位实习成绩汇总表</span></p><p><br></p>');
INSERT INTO content
                    VALUES (159, '<p style="text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">各学院：</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">为切实做好我校2025届本科毕业设计（论文）工作，保证我校此项工作顺利进行，提高效率，保证质量，学校决定启动2025届本科毕业设计（论文）工作，现将有关事项通知如下：</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">一、时间安排</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">1.2024年9月，各学院启动毕业设计（论文）工作，组织师生学习教育部《学位论文作假行为处理办法》、《本科毕业论文（设计）抽检办法（试行）》和《江西软件职业技术大学本科毕业论文（设计）工作管理办法（修订）》，9月20日前将毕业设计（论文）工作计划报送到教务处实践教学科。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">2.2024年9月30日前，各学院完成选题工作，提交《选题一览表》到教务处实践教学科。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">3.2024年10月31日前，各学院完成开题工作。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">4.2025年2月28日前，各学院完成毕业设计（论文）中期检查工作。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">5.2025年4月10日前，各学院完成毕业设计（论文）检测查重工作，并将答辩安排计划报送至教务处实践教学科。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">6.2025年4月30日前，各学院完成答辩及成绩评定工作，同时报送优秀毕业设计（论文）名单。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">7.2025年5月30日前，各学院完成毕业设计（论文）的总结工作，报送毕业论文总结纸质材料和电子版到教务处实践教学科。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">二、总体要求</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">1.根据各专业人才培养方案的具体要求，在执行学校关于本科毕业论文（设计）工作管理办法规定的基础上，强化和完善各专业毕业设计（论文）的规范化要求与管理，合理安排工作程序和进度，围绕选题、开题、教师指导、中期检查、论文定稿、评阅、答辩等环节，制定具体的工作计划和实施方案。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">2.各专业应加大毕业设计（论文）工作研究力度，根据各专业特点，探索毕业设计（论文）教学新模式，创造性地开展毕业设计（论文）的管理工作。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">3.校内指导教师指导学生人数原则上不超过10人，校外指导教师指导学生人数原则上不超过6人。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">4.在选题环节，把好“选题”关。各专业应组织指导教师认真研究、拟定毕业设计（论文）题目，来自于生产实践、真实项目的毕业设计（论文）题目须占比50%以上，题目数量应为学生人数的120%以上。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">5.指导教师要线上线下结合，加强学生毕业设计（论文）指导，尽职尽责，确保毕业设计（论文）工作有序开展。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">6.加大检查力度，做好毕业设计（论文）工作过程监控，重点检查学风、工作进度和教师指导情况，确保毕业设计（论文）工作有序推进。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">7.毕业论文（设计）工作全部完成后，各学院应按照学校要求，做好相关资料的归类整理和存档工作。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">8.毕业论文（设计）存档资料清单见附件。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">9.各类资料须于规定时间前报送至教务处实践教学科，联系人：李秋霞，18179109398。</span></p><p style="text-indent: 28pt; text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">10.未尽事宜，请参照本科毕业论文（设计）指导手册。</span></p><p style="text-indent: 28pt; text-align: right;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;"> </span></p><p style="text-indent: 28pt; text-align: right;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;">江西软件职业技术大学教务处</span></p><p style="text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;"> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2024年9月5日</span></p><p style="text-align: center;"> </p><p style="text-indent: 28pt; text-align: center;"> </p><p style="text-align: justify;"><span style="color: rgb(0, 0, 0); background-color: rgb(255, 255, 255); font-family: 宋体;"> </span></p><p style="text-align: justify;"><span style="color: rgb(0, 0, 0);"><strong>附件</strong></span></p><p style="text-align: center;"><span style="color: rgb(0, 0, 0);"><strong>毕业论文（设计）存档资料清单</strong></span></p><p style="text-align: center;"> </p><p style="text-indent: 28pt; text-align: left;"> </p><p style="text-indent: 28pt; text-align: left;"><span>1.本科毕业设计（论文）开题报告及任务书</span></p><p style="text-indent: 28pt; text-align: left;"><span>2.本科毕业论文（设计）指导教师指导过程记录表</span></p><p style="text-indent: 28pt; text-align: left;"><span>3.本科毕业论文（设计）中期检查表 </span></p><p style="text-indent: 28pt; text-align: left;"><span>4.本科毕业设计指导教师评阅表</span></p><p style="text-indent: 28pt; text-align: left;"><span>5.本科毕业论文指导教师评阅表</span></p><p style="text-indent: 28pt; text-align: left;"><span>6.本科毕业设计评阅教师评阅表</span></p><p style="text-indent: 28pt; text-align: left;"><span>7.本科毕业论文评阅教师评阅表</span></p><p style="text-indent: 28pt; text-align: left;"><span>8.本科毕业论文（设计）答辩资格审查表</span></p><p style="text-indent: 28pt; text-align: left;"><span>9.本科毕业论文（设计）答辩委员会评定表</span></p><p style="text-indent: 28pt; text-align: left;"><span>10.本科毕业设计（论文)答辩记录表</span></p><p style="text-align: justify;"><span style="font-family: 宋体;"> </span></p>');
