INSERT INTO content
                    VALUES (161, '<p> <a href="http://jwc.jxuspt.edu.cn/resource_znkj/20250109/677f7f1cb760ba23a2900af0.pdf" target="_blank">1.关于印发《江西软件职业技术大学课程考核工作规程（2024修订）》的通知</a> </p><p> <a href="http://jwc.jxuspt.edu.cn/resource_znkj/20250105/677a2599b760ba23a2900aef.zip" target="_blank">2.江西软件职业技术大学课程考核工作规程及考试相关附件</a> </p>');
