OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9cnGC44NfwcO37SZDGXwmm6KdQA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A42%3A52%E5%9B%BE%E7%89%878.png?Expires=2063842972&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9cnGC44NfwcO37SZDGXwmm6KdQA%3D" alt="" width="650" height="434" /></a><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A43%3A03%E5%9B%BE%E7%89%879.png?Expires=2063842983&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=kiPMFBd8QrOxk0C8poj7WCy1QOo%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A43%3A03%E5%9B%BE%E7%89%879.png?Expires=2063842983&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=kiPMFBd8QrOxk0C8poj7WCy1QOo%3D" alt="" width="650" height="434" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">最后，艺委会成员与江西软件大学VR与艺术学院师生共同参加了由企业代表上海鸿宇科技总经理雷菁昉主讲的《人工智能为艺术设计赋能》专题讲座，共同感受人工智能对未来艺术专业领域发展的影响。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A43%3A32%E5%9B%BE%E7%89%8710.png?Expires=2063843012&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=%2FtzUtbxSuixX2%2F2eIcfi0mokihE%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A43%3A32%E5%9B%BE%E7%89%8710.png?Expires=2063843012&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=%2FtzUtbxSuixX2%2F2eIcfi0mokihE%3D" alt="" width="650" height="433" /></a><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A44%3A00%E5%9B%BE%E7%89%8711.png?Expires=2063843040&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Sjm8tJPgnIyywrzqVSae02L%2FuTU%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A44%3A00%E5%9B%BE%E7%89%8711.png?Expires=2063843040&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Sjm8tJPgnIyywrzqVSae02L%2FuTU%3D" alt="" width="650" height="433" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">&nbsp;本次艺委会重点工作会议是继第四届江西省职业教育学会艺术专业委员会换届工作后召开的一次重要会议，会议明确了艺委会的机构架构，指明了艺委会未来发展方向和目标。未来，江西省职业教育学会艺委会将进一步秉承"服务、交流、合作、发展"的宗旨，不断创新工作思路和方法，努力开创艺委会工作的新局面。</span></p>');
INSERT INTO content
                    VALUES (189, '<p>Hello, World!</p>');
INSERT INTO content
                    VALUES (190, '<p style="text-indent: 24pt; text-align: justify; line-height: 22pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt;" align="justify"><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">2024年9月2日，江西省职业院校技能大赛执委会公布 2024 年江西省职业院校技能大赛协办单位及承办院校名单。经专家组评审并报大赛组委会审定，确定了2024年拟定常规赛项 153 项（高职组 99 项，中职组 54 项），特色赛项 56 项（高职组 29 项，中职组 27 项）。其中，我校将承办高职组的电子与信息大类的&ldquo;网络舆情监测与分析&rdquo;以及&ldquo;Web 应用软件开发&rdquo;赛项等2项赛事。</span></span></p>
<p style="text-indent: 24pt; line-height: 22pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt;" align="justify"><span style="font-family: Calibri; font-size: 10.5000pt;">&nbsp;</span><span style="font-family: Calibri; font-size: 10.5000pt;"> <img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20240910/66dfef6cb760ba236ed6d346.png" /><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20240910/66dfef6cb760ba236ed6d347.png" /></span></p>
<p style="text-indent: 24pt; text-align: justify; line-height: 22pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt;" align="justify"><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">江</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">西省职业院校技能大赛是我省职业教育的一项重大制度设计和创新，在服务</span><span style="font-family: 方正仿宋_GB2312;">&ldquo;三教&rdquo;改革、推动职业教育高质量发展方面发挥了重要作用。大赛涵盖了多个学科和领域，涉及多个层次和类型的职业院校，具有广泛的参与性和综合性</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">，</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">为职业院校</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">师生</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">提供了一个交流互鉴的平台，</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">为</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">进一步提升我省技术技能人才培养质量</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">，起到了</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">&ldquo;树旗、导航、定标、催化&rdquo;</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">的</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">作用</span></span><span style="font-family: 方正仿宋_GB2312; font-size: 12.0000pt;"><span style="font-family: 方正仿宋_GB2312;">。</span></span></p>');
INSERT INTO content
                    VALUES (191, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">近日，第五届江西省高校教师教学创新大赛获奖名单公布。我校新媒体学院杨婧教师团队主讲的《融合新闻作品创作》获课程思政中级及以下组三等奖，VR与艺术学院李书烨教师团队主讲的《创新设计 I》获新文科副高组三等奖。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: 仿宋; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-size: 18px; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-03%2009%3A04%3A28image.png?Expires=2064272669&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=B1Adc63E0d%2FRNvV8eu8wD%2FL8ifY%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-03%2009%3A04%3A28image.png?Expires=2064272669&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=B1Adc63E0d%2FRNvV8eu8wD%2FL8ifY%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: 仿宋; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-size: 18px; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-03%2009%3A05%3A009acb0ef74e527fc60cb5116bbbc66a1.png?Expires=2064272701&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=E6sKM7IKkE3uQ1pEmoDQl110eVw%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-03%2009%3A05%3A009acb0ef74e527fc60cb5116bbbc66a1.png?Expires=2064272701&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=E6sKM7IKkE3uQ1pEmoDQl110eVw%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">本届大赛由江西省教育厅指导、江西省高等教育学会主办，以&ldquo;推动教学创新，培养一流人才&rdquo;为主题，包括基础课程、新工科、新文科、新农科、新医科、课程思政和产教融合7个赛道，汇聚了全省高校众多优秀教师同台竞技。经校赛、省赛两轮严格评审，最终评选出一等奖40项、二等奖85项、三等奖90项，优秀组织奖16项。作为教育部&ldquo;三评一竞赛&rdquo;权威赛事之一，其成绩已纳入江西省高等教育质量评估体系，成为衡量高校教学改革成效的重要内容。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">近年来，我校高度重视教学创新与教师队伍建设，积极鼓励教师开展教学改革与实践，为教师搭建各类教学能力提升平台，通过&ldquo;以赛促教、以赛促改、以赛促建&rdquo;的方式，鼓励教师积极投身教学创新，有力推动人才培养的高质量发展。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;">&nbsp;</p>');
INSERT INTO content
                    VALUES (192, '<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">1</span><span style="font-size: 16pt;">1</span><span style="font-size: 16pt;">月</span><span style="font-size: 16pt;">2</span><span style="font-size: 16pt;">5日</span><span style="font-size: 16pt;">下</span><span style="font-size: 16pt;">午，</span><span style="font-size: 16pt;">我校</span><span style="font-size: 16pt;">在行政楼</span><span style="font-size: 16pt;">一</span><span style="font-size: 16pt;">楼会议室召开了2025年拟招生专业设置工作会议</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">旨在进一步优化学校专业结构，</span><span style="color: #000000; font-size: 16pt;">提升主干专业、重点发展专业服务产业适配度。</span><span style="font-size: 16pt;">教务处、质量监测与评估中心、人事处、招就处、职培中心、实验实训管理中心、资产管理中心、校企合作办负责人，各学院教学副院长</span><span style="font-size: 16pt;">、</span><span style="font-size: 16pt;">教务科长等相关负责人</span><span style="font-size: 16pt;">参加了会议</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">副校长傅志军主持会议并讲话。</span></span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241216/675fcccfb760ba23a2900ae7.png" /></span></span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify">&nbsp;</p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">会议伊始，教务处</span><span style="font-size: 16pt;">处长李嵩</span><span style="font-size: 16pt;">对江西省教育厅办公室下发的《关于做好江西省2025年职业教育拟招生专业设置管理工作的通知》</span><span style="font-size: 16pt;">进行了详细解读，</span><span style="font-size: 16pt;">说明了各项附件的填写方法和注意事项，</span><span style="font-size: 16pt;">明确了下一步的工作要求和时间节点。与会人员围绕拟招生专业设置的具体问题进行了深入讨论，并提出了许多建设性意见和建议</span><span style="font-size: 16pt;">。</span></span></p>
<p style="margin-right: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; margin-bottom: 10pt; margin-left: 6pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">副校长傅志军在会上对几项重点工作进行提示，一是加强2025届毕业学生实习安全和毕业设计（论文）管理工作。加强实习过程的安全监管，保障学生人身及财产安全，毕业生辅导员、论文指导教师要加强与学生的联系，加强过程管理和质量监控，实时跟进学生论文进度。</span><span style="font-size: 16pt;">二是认真准备2025年拟申报的本、专科专业评审会</span><span style="font-size: 16pt;">。要早做准备，</span><span style="font-size: 16pt;">积极听取专家建议</span><span style="font-size: 16pt;">。</span><span style="font-size: 16pt;">三是</span><span style="font-size: 16pt;">进一步规范期末考试试卷命题工作</span><span style="font-size: 16pt;">。四是</span><span style="font-size: 16pt;">高度重视拟招生专业设置工作</span><span style="font-size: 16pt;">。各学院要</span><span style="color: #000000; font-size: 16pt;">充分认识</span><span style="color: #000000; font-size: 16pt;">到</span><span style="color: #000000; font-size: 16pt;">专业设置工作的重要性，严格按照规定程序、时间和标准完成</span><span style="color: #000000; font-size: 16pt;">提交</span><span style="color: #000000; font-size: 16pt;">工作</span><span style="color: #000000; font-size: 16pt;">。要</span><span style="font-size: 16pt;">紧紧围绕国家及区域建设现代化产业体系的需求，结合学校未来的建设发展规划，对照教育部职业教育标准，科学合理地调整专业设置。</span></span></p>');
INSERT INTO content
                    VALUES (193, '<p>&nbsp; &nbsp; &nbsp; &nbsp;本学年学校共设置有20个本科专业，22个专科专业。本学年，本科新增人工智能工程技术、金融科技应用、大数据与审计、影视编导、物联网工程技术专业，专科现代通信技术专业停招。</p>
<p>&nbsp;</p>
<p><a title="附件1：江西软件职业技术大学设置专业一览表(2023-2024学年)" href="http://jwc.jxuspt.edu.cn/resource_znkj/20241111/6731791eb760ba23a2900adf.xlsx">附件1：江西软件职业技术大学设置专业一览表(2023-2024学年)</a></p>
<p><a title="附件2：江西软件职业技术大学停招专业一览表（2023-2024学年）" href="http://jwc.jxuspt.edu.cn/resource_znkj/20241111/67317943b760ba23a2900ae0.xlsx">附件2：江西软件职业技术大学停招专业一览表（2023-2024学年）</a></p>
<p><a title="附件3：江西软件职业技术大学新增专业一览表（2023-2024学年）" href="http://jwc.jxuspt.edu.cn/resource_znkj/20241111/67317961b760ba23a2900ae1.xlsx">附件3：江西软件职业技术大学新增专业一览表（2023-2024学年）</a></p>');
INSERT INTO content
                    VALUES (194, '<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">近日，江西省教育厅公布了重点实验室立项</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">名单</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">软件工程学院、智能科技学院、北斗通航研究院联合</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">申报的&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">北斗通航与应用</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">重点实验室&rdquo;获批，成为我校首个</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">江西省教育厅</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">重点实验室。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&nbsp;这一成果标志着学校在科研创新与技术开发方面取得重要进展，进一步增强了学校在</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">北斗导航、无人机、云计算等</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">学科领域的科研实力，为学科平台建设注入了强劲动力。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A31%E5%9B%BE%E7%89%871.png?Expires=2051249611&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=0tbCHT6cA4EfnbWTjsMjzWAwWCc%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 350px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A31%E5%9B%BE%E7%89%871.png?Expires=2051249611&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=0tbCHT6cA4EfnbWTjsMjzWAwWCc%3D" alt="" width="650" height="350" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A49%E5%9B%BE%E7%89%872.png?Expires=2051249630&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9c2QpSe%2FRFJGyBFlQBeH1TpJetA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 767px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A49%E5%9B%BE%E7%89%872.png?Expires=2051249630&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9c2QpSe%2FRFJGyBFlQBeH1TpJetA%3D" alt="" width="650" height="767" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">实验室将紧密对接江西省</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">1269</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&rdquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">行动计划</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">和</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&ldquo;江西省推进北斗产业发展若干措施&rdquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">发展重大需求</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">突破无人机低空航路规划、云端综合管控和高精度定位等关键技术，为低空通航产业提供技术支持，并促进相关产业链的发展</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">研究成果将直接服务于无人机物流配送、农业遥感监测、应急救援等领域，为地方经济发展注入新动力。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">实验室将加强与</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">有关</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">高校、科研机构及企业合作与交流</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">吸引优秀科研人员和学生参与研究工作，培养一批掌握前沿技术的专业人才，推动相关学科之间的交叉融合，探索新的教学模式，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">努力</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">成为省内领先、国内知名的科研平台。</span></span></p>');
INSERT INTO content
                    VALUES (195, '<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;">12月6日上午，我校在行政楼一楼会议室召开了2024-2025学年第一学期第四次教学工作例会，旨在对11月份教学管理及检查工作进行总结汇报，并布置12月份的具体工作。教务处、质量监测与评估中心负责人，各教学院（部）院长（主任），教学副院长（副主任），教务科长等相关负责人参加了会议，副校长傅志军主持会议并讲话。</span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241216/675fcebab760ba23a2900ae9.png" /></span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify">&nbsp;</p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;">会议听取了校督导组对于11月份教学活动月督查情况的汇报，总体来看，我校教学活动月举办较为成功，对于提升教师的教学水平起到了一定作用，是一次非常好的教学改革尝试。</span></p>
<p style="margin-right: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; margin-bottom: 10pt; margin-left: 6pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;">教务处处长李嵩对11月份工作进行了总结，并对下一阶段的本、专科专业备案工作、新增专业申报工、学士学位授权专业申报、期末考试安排、岗位实习、毕业设计（论文）等重点工作做了布置安排。教务处副处长王金林对期中教学检查情况进行了通报，结合发现的问题和师生建议反馈，对教学资料、试卷阅卷、教案编写、实验（训）报告、档案室建设等方面做了进一步的规范。</span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;">会上，副校长傅志军对各教学院（部）在教学活动月付出的努力表示了认可，总结此次教学活动月内容丰富、效果良好，今后要把教学活动月作为教学工作中的基本环节加以坚持。同时强调12月份工作要规范、有序地进行谋划。</span><span style="font-family: 微软雅黑; font-size: 24px; color: #000000;">一是期末考试工作要规范。从命题、制卷、考试、阅卷到成绩评定与录入等，每一个环节都要严格按照既定流程执行，确保考试的公平、公正和有效性。二是涉及本、专科专业申报方面的4项工作要按规定按时保质申报和提交。三是有序推进2025届毕业生岗位实习工作。关心关爱学生，关注学生实习安全，在做好岗位实习工作的同时，兼顾好毕业设计（论文）。四是有条不紊地组织好全国大学英语四、六级考试。五是做好2025版人才培养方案，教务处与公共课教学部要加强联系，各学院要提前捋清本专业的专业基础课、专业核心课、专业选修课并形成目录。六是谋划好本科专业发展规划，拓宽思路，明确好专业发展方向和特色。七是完成好课程建设工作，不断更新和优化课程内容和教学方法，以适应学科发展和学生需求的变化。八是做好2024年总结及2025年工作计划，高度重视，站位要高，对照本科教学合格评估指标，谋划好明年的工作。</span></p>
<p style="margin-bottom: 10pt; font-family: Tahoma; font-size: 11pt;"><span style="font-family: 微软雅黑; font-size: 16pt;">&nbsp;</span></p>');
INSERT INTO content
                    VALUES (196, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">近日，为积极响应教育部等九个部门关于开展全国推广普通话宣传周活动的号召，并庆祝教师节、中秋节和国庆节等重要节庆日，我校成功举办了一场别开生面的校园推普海报设计大赛。经评选，此次大赛产生了一等奖1名、二等奖2名、三等奖3名。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-23%2010%3A40%3A16image.png?Expires=2042419216&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=MhFxvj2tJ91rydzWQ8dlepqMn%2BU%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-23%2010%3A40%3A16image.png?Expires=2042419216&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=MhFxvj2tJ91rydzWQ8dlepqMn%2BU%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">本次海报设计大赛以&ldquo;加大推普力度，筑牢强国语言基石&rdquo;为主题，通过学生们的创意作品，充分展示了普通话的独特魅力。活动由教务处负责，VR与艺术学院承办，面向全校学生公开征集作品。学生们积极响应，巧妙地将教师节、中秋节和国庆节等节日元素融入海报设计中，创作出一幅幅富有创意和视觉冲击力的海报。这些优秀作品在校内学术报告厅进行展示，吸引了学生广泛关注。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">此次活动不仅为学生提供了一个展示才华和创意的平台，加深了他们对传统节日的理解和认识，还有效提升了他们的普通话水平和语言文字规范意识。同时，它也在全校范围内营造了浓厚的推广普通话的氛围和文化氛围。未来，我校将继续举办此类活动，进一步推动语言文字工作的深入开展，为铸牢中华民族共同体意识、传承和弘扬中华优秀语言文化奠定坚实的基础。</span></p>');
INSERT INTO content
                    VALUES (197, '<p><a title="赣学位办〔2024〕4号  关于公布江西省高等学校2024年新增学士学位授权专业名单的通知" href="http://jwc.jxuspt.edu.cn/resource_znkj/20241111/673176b4b760ba23a2900ade.pdf">赣学位办〔2024〕4号 关于公布江西省高等学校2024年新增学士学位授权专业名单的通知</a></p>');
INSERT INTO content
                    VALUES (198, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">在第四十个教师节来临之际，为弘扬尊师重教的优良传统，增强新进青年教师的责任感和使命感，9月9日下午，我校在行政楼一楼会议室举行了青年教师座谈会。党委副书记、执行校长范红铭，教务处、人事处、科技处、后勤保障处等职能部门负责人及20余名青年教师代表参加了会议。傅志军副校长主持会议并讲话。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-12%2016%3A20%3A33image.png?Expires=2041489233&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KsSdq2mRXnrqqr1kEueztNBAsLA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-12%2016%3A20%3A33image.png?Expires=2041489233&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KsSdq2mRXnrqqr1kEueztNBAsLA%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">执行校长范红铭向全体新进青年教师表达了热烈的欢迎和衷心的祝贺。他指出，青年教师是学校发展的生力军，要高度重视青年教师的培养工作，提升教师的工作积极性和幸福感。学校职能部门要增强服务意识，以师为尊，坚定支持青年教师成长与发展。他强调，青年教师肩负着培养社会主义建设者和接班人的重任，应始终坚持党的教育方针，坚定理想信念，落实立德树人的根本任务。最后，他希望全体青年教师能够牢记使命、不负重托，为建设有特色、有品质、 有情怀、有作为的高水平职业技术大学而努力。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">副校长傅志军对新进青年教师提出了三点殷切期望：一是坚守教育初心，担当育人使命；二是加强学习，提升综合素质，增强教书育人的能力；三是尽快适应角色的转换，发挥个人所长，做好教书育人工作，为学校发展做出贡献。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">教务处处长李嵩和后勤处处长谢文平发言，表示学校将持续关注青年教师的成长，提供必要的支持与保障，同时积极倾听青年教师的声音，解决他们在工作和生活中遇到的问题，共同营造一个和谐、积极的工作环境。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">新进青年教师代表先后发言，分享了他们加入学校以来的心路历程，表达了对学校的热爱以及对未来工作的期许。他们纷纷表示，作为高校教师队伍的新生力量，将以饱满的热情和坚定的信念投身到教育事业中，为学生的成长和学校的发展贡献自己的力量。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">本次座谈会的成功举办，不仅展现了我校对青年教师的重视，也彰显了学校致力于培养高素质教师队伍的决心。期待青年教师能够在学校的支持下，不断成长，为学校的未来发展注入新的活力。</span></p>');
INSERT INTO content
                    VALUES (199, '<p style="text-indent: 2em; line-height: 2; text-align: justify;" align="justify"><span style="font-family: 微软雅黑;">1月3日，我校在行政楼一楼会议室召开了2024-2025学年第一学期第五次教学工作例会。教务处、质量监测与评估中心负责人，各教学院（部）院长（主任）、教学副院长（副主任）、教务科长等相关负责人参加了会议。副校长傅志军主持会议并讲话。</span></p>
<p style="text-indent: 2em; line-height: 2; text-align: justify;" align="justify"><span style="font-family: 微软雅黑;">会议伊始，校督导组组长黄承烈对12月份的教学督查情况进行了通报。总体来看，本月教学秩序整体平稳，延续了11月教学活动月的积极成果。智能科技学院副院长蒋淦华和软件工程学院副院长李俊传达了北京职业教育项目课程建设研讨会的会议精神。他们围绕职业本科的内涵、&ldquo;五金&rdquo;体系建设、课程设置、专业设置以及人才培养方案的制定等多个层面进行了深入的分享与交流。</span></p>
<p style="text-indent: 2em; line-height: 2; text-align: justify;" align="justify"><span style="font-family: 微软雅黑;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20250228/67c12bc0b760ba23a2900af3." /></span></p>
<p style="text-indent: 2em; line-height: 2; text-align: justify;"><span style="font-family: 微软雅黑;">教务处对近期的工作进行了回顾与安排，强调要抓好期末考试考风考纪，认真完成收尾工作，通报了毕业论文（设计）及岗位实习工作情况，对2024-2025学年第二学期教材征订工作提出了要求，并下发校级毕业设计（论文）抽检管理办法征求意见���，征集各学院反馈意见。</span></p>
<p style="text-indent: 2em; line-height: 2; text-align: justify;" align="justify"><span style="font-family: 微软雅黑;">会上，傅校长重点强调了几项工作：一是要扎实做好期末考试工作，除了确保考试过程的公平公正，还需细致做好成绩评阅、登分，试卷分析等工作，以便精准反馈教学效果，指导后续教学改进。二是加强本科合格评估材料学习，深入学习理解评估标准，按合格评估指标规范开展各项教学与管理工作。三是高度重视2025届毕业论文（设计）和岗位实习工作，加强过程管理，确保质量达标。四是2025版人才培养方案制定，调整课程设置，强化实践教学，合理规划教学进度、创新课程考核形式，打造特色鲜明的人才培养方案，促进学生全面发展。</span></p>');
INSERT INTO content
                    VALUES (200, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">3月28日，我校在A1-102会议室组织召开了2024-2025学年第二学期第三次教学工作例会，教务处、质量监测与评估中心负责人及部门相关人员，各教学院（部）院长（主任），教学副院长（副主任），教务科长等相关负责人参加会议。副校长傅志军主持会议并讲话。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-14%2019%3A56%3A50%E5%9B%BE%E7%89%871.png?Expires=2059991811&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=6JxqK0ZHGIeLB2vxVL7iO%2BdGfgs%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 422px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-14%2019%3A56%3A50%E5%9B%BE%E7%89%871.png?Expires=2059991811&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=6JxqK0ZHGIeLB2vxVL7iO%2BdGfgs%3D" alt="" width="650" height="422" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">会议通报了3月份教学督查与实验（训）专项检查情况。从整体来看，教学运行秩序良好，但部分环节仍需改进，对于存在的共性问题要予以重视。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">会议对2025届毕业班学生毕业设计（论文）答辩工作和岗位实习工作提出了要求，并对即将启动的期中教学检查以及近期技能竞赛工作进行了安排，传达了江西省教育厅全省高校招生培养就业联动工作视频会精神，强调了要进一步推进招生计划、人才培养和就业联动机制，提升人才培养质量和服务经济社会发展能力，全面促进毕业生高质量充分就业等。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">副校长傅志军对近期工作重点提出了三点意见：一是要围绕职业教育的属性，解放思想，转变观念。深化校企合作与产教融合，确保专业设置对接国家战略，人才培养规格对接岗位要求，教学内容对接先进工艺、先进技术，教学过程对接企业生产过程，实现&ldquo;理论教学案例化、实践教学项目化、毕业设计实干化&rdquo;。二是要加强学习、担当实干，要认真学习职业教育本质，理解并应用于管理当中，加强基层教学单位和教师的指导，提高教师的能力和水平。三是具体工作布置，包括落实好&ldquo;拓尔思&rdquo;实训项目、认真打磨教学课件、实验（训）指导书编制规范和校外实习基地检查等工作。</span></p>');
INSERT INTO content
                    VALUES (201, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">8月29日下午，我校在行政楼一楼会议室召开了2024-2025学年第一学期第一次教学工作例会。党委副书记、执行校长范红铭出席会议并讲话，副校长傅志军主持会议。教务处、学工处、质评中心、实验实训中心、校企合作办等职能部门负责人，各教学院（部）院长（主任）、教学副院长（副主任）、教务科长及教务处人员等参加了会议。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-03%2012%3A18%3A04image.png?Expires=2040697085&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=wZjknYf1n6aVWmnNBsEwWRmBhZ0%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-03%2012%3A18%3A04image.png?Expires=2040697085&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=wZjknYf1n6aVWmnNBsEwWRmBhZ0%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">执行校长范红铭强调，教学质量是学校的生命线，新学期要继续坚持问题、目标导向，注重工作细节，扎实做好本学期的教学与管理工作。一是做好本学期教学工作安排，提高教学管理的质量与水平。认真负责地做好学期初各项教学准备、教学资源保障等工作，在工作中要多思考，创新工作思路，提升工作实效性，注重教学成果转化，形成教学合力，高效有序地开展教学工作。二是加强教师队伍建设，提升教学水平和课堂质量。全体教师要树立质量意识，提升教学水平和专业素养，教学有方法，课堂有温度，不断帮助青年教师成长，着力打造优质高效队伍。三是做好实习实训工作，强化实践教学。高度重视实习实训工作，加强与行业企业的合作，继续建立稳定的校外实习基地，强化实习实训过程管理，为学生提供真实的工作环境和实践机会。四是聚焦本科教学合格评估指标体系，提升教育教学质量。各学院（部）要加强各项工作的统筹安排，有针对性地开展教学工作，优化教育教学内容，持续改进和提升教育教学质量。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">副校长傅志军明确提出，新学期的教学与管理工作要以平稳、有序、规范作为基本要求和遵循，紧紧围绕本科教学合格评估指标体系开展各项工作；管理干部要加强学习，不断优化管理流程、改进工作方法、提升工作效率，扎实推进各项工作的落实；各教学院（部）要确保期初教学工作和活动有序进行；重点做好2025届毕业生论文（设计）、岗位实习、本科专业申报以及人才培养方案修订等工作。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">教务处处长李嵩布置了新学期期初教学重点工作，就人才培养工作状态数据采集与管理平台填报工作、期初教学检查工作、2025届毕业班学生岗位实习、毕业论文（设计）抽检等工作作了详细工作要求。质量监测与评估中心督导夏璇全面回顾上一学年的教学督导，并对本学期督导工作进行了部署。</span></p>');
INSERT INTO content
                    VALUES (202, '<p align="justify"><span style="font-family: 仿宋;">&nbsp; <span style="font-family: 微软雅黑;">&nbsp;<span style="font-size: 24px;">为扎实推进我校毕业班学生</span></span></span><span style="font-family: 微软雅黑; font-size: 24px;">岗位实习工作，切实解决工作中遇到的问题，10月31日，我校在行政楼一楼会议室召开了2025年毕业班学生岗位实习工作推进会。执行校长范红铭、教务处、校企���作办负责人，各学院院长及教学副院长参加了会议，副校长傅志军主持会议并讲话。</span></p>
<p align="justify"><span style="font-family: 微软雅黑; font-size: 24px;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241126/67453f83b760ba23a2900ae4.png" /></span></p>
<p align="justify"><span style="font-family: 微软雅黑; font-size: 24px;">&nbsp; 会上各学院对于本学院集中实习安排现状、集中实习公司数量、提供的岗位数（是否充足）、是否做了集中实习宣讲、是否做了对应的集中实习计划、各计划是否配套了指导教师跟踪、目前集中实习安排工作问题及难点、学生实习意愿等方面进行了汇报，分享了各自在实习工作中的亮点和成效，提出了当前实习工作中存在的共性和个性问题。</span></p>
<p align="justify"><span style="font-family: 微软雅黑; font-size: 24px;">&nbsp; 在听取了各学院的汇报和讨论后，执行校长范红铭对2025届学生岗位实习管理工作提出三点要求：一是提高思想认识，强化责任担当。学院要进一步提高对岗位实习工作的重视程度，对标对表的落实本科合格评估指标体系。二是理清头绪，形成合力，动实习就业一体化。各教学单位要准确把握专业定位，细化学生岗位实习的分工安排，加强交流协作，借力借智，共同克服困难，推进各项工作内容落实落细。三是就业工作要潜移默化，贯穿于实习的全过程。实习和就业工作的宣传要潜移默化贯穿于各学习阶段，深化学生对于实习就业的认识，并根据学生的专业特点和实习需求适当调整人才培养方案，采取分段式实习，通过逐步深入的方式，努力高质量完成2025届学生岗位实习管理工作。</span></p>
<p align="justify"><span style="font-family: 微软雅黑; font-size: 24px;">&nbsp; 副校长傅志军在会上强调了开展集中实习的重要性，一是基于江西省职业学校学生实习管理平台填报要求，二是本科合格评估的要求，三是提高学生就业率的现实考虑。各教学单位要转变观念，落实上级要求，加强对学生的管理，将实习管理工作做细做实；加强与企业的合作与交流，不断优化实习资源配置，实习基地要重点以南昌周围为主，便于评估专家实地考核；完善实习成果的考核与评估体系，客观公正地评价学生的实习表现。</span></p>');
INSERT INTO content
                    VALUES (203, '<p style="text-indent: 30pt; line-height: 26pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">近日，江西省高等教育学会举办的2024年度第一届&ldquo;格子达杯&rdquo;优秀本科毕业论文评奖活动结果公布，我校共获得优秀论文指导奖&ldquo;优秀奖&rdquo;3项���优秀论文奖&ldquo;优秀奖&rdquo;3项。</span></p>
<p style="text-indent: 21pt; line-height: 26pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt; text-align: justify;" align="justify"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20250228/67c12a77b760ba23a2900af2.png" /></p>
<p style="text-indent: 21pt; line-height: 26pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">此次&ldquo;格子达杯&rdquo;优秀本科毕业论文评奖活动，旨在表彰在学术研究、创新思维和实践能力方面表现突出的本科毕业生。我校高度重视本科毕业论文（设计）工作，为加强我校毕业论文（设计）工作的规范管理，进一步提高毕业论文（设计）质量，制发了《江西软件职业技术大学本科毕业论文（设计）指导手册》等文件，为毕业论文（设计）工作提供了制度与组织保障。</span></p>
<p style="text-indent: 21pt; line-height: 26pt; margin: 0pt 0pt 0.0001pt; font-family: Calibri; font-size: 10.5pt; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">在此，特向获奖学生及指导教师表示热烈的祝贺！希望全体同学以获奖同学为榜样，勤奋学习、勇于创新，在今后的学术研究和学习实践中取得更优异的成绩。同时，也希望全体教师继续发扬敬业精神，不断提升教学质量和科研水平，为培养更多具有创新能力和实践能力的高素质人才贡献力量。</span></p>');
INSERT INTO content
                    VALUES (204, '<p style="text-align: justify; text-indent: 2em;" align="justify"><span style="font-family: 宋体; font-size: 18px;"><span style="font-size: 24px; font-family: 微软雅黑;">10月8日上午，我校在行政楼一楼会议室召开了2024-2025学年第一学期第二次教学工作例会。教务处、质量监测与评估中心负责人、各教学院（部）院长（主任），教学副院长（副主任），教务科长等相关负责人参加了会议，副校长傅志军主持会议并讲话。</span></span></p>
<p align="justify"><span style="font-family: 微软雅黑; font-size: 24px;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241126/6745412bb760ba23a2900ae6.png" /></span></p>
<p style="text-align: justify; text-indent: 2em;" align="justify"><span style="font-size: 24px; font-family: 微软雅黑;">会上，教务处对9月份工作进行了总结，并布置了10月份工作：1.落实好毕业生岗位实习工作，对集中实习和自主实习做好摸底；2.做好毕业生毕业论文（设计）工作，把好&ldquo;选题关&rdquo;、&ldquo;过程关&rdquo;、&ldquo;质量关&rdquo;；3.对标对表按时完成本科教学合格评估自查工作报送材料；4.做好2025年新设本科申报工作和本科专业建设发展规划工作；5.做好高等教育质量监测国家数据平台填报工作。</span></p>
<p style="text-align: justify; text-indent: 2em;" align="justify"><span style="font-size: 24px; font-family: 微软雅黑;">副校长傅志军在会上对教学管理工作提出要求：一是要加强学习，提高能力。他强调，全体教学管理人员及教师应不断提升自我，通过持续学习增强专业素养。在日常工作中，要注重培养发现问题和解决问题的能力，确保教学工作的高效运行。</span></p>
<p style="text-align: justify; text-indent: 2em;" align="justify"><span style="font-family: 微软雅黑; font-size: 24px;">二是要转变观念，求真务实。必须紧跟时代步伐，转变观念，摒弃形式主义，要认真扎实地做好每一项工作，坚持实事求是，确保教学质量和教学管理的实效性。</span></p>
<p style="text-align: justify; text-indent: 2em;" align="justify"><span style="font-size: 24px; font-family: 微软雅黑;">三是具体工作安排。1.做好2025年新设本科申报工作和本科专业建设发展规划工作。各学院需积极准备，严格按照教育部及学校的相关规定和要求开展相关工作；2.做好期中教学检查工作。教务处要组织好期中教学检查，各教学院（部）需提前做好自查工作，并针对检查中发现的问题及时整改；3.通报11月份教学活动月安排。为促进教师间的交流与合作，提升教师教学水平，学校将于11月份举办教学活动月，活动内容包括教师公开课、青年教师沙龙和师生座谈会等。</span></p>');
INSERT INTO content
                    VALUES (205, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">4月30日，第十六届蓝桥杯全国软件和信息技术专业人才大赛江西赛区获奖名单公布，我校学生凭借扎实的专业功底与卓越的创新能力，斩获省级一等奖15项，省级二等奖51项，省级三等奖98项，共计164个奖项，获奖率达40%，其中获省级一等奖的同学直接晋级全国赛。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A14%3A13image.png?Expires=2062653253&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=DNQy7wk4q3SYP7UtW9ObxYhD%2BAY%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A14%3A13image.png?Expires=2062653253&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=DNQy7wk4q3SYP7UtW9ObxYhD%2BAY%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">蓝桥杯大赛由工业和信息化部人才交流中心主办，国信蓝桥教育科技股份有限公司承办的一项面向全国高校大学生的竞赛，连续五年入选中国高等教育学会 &ldquo;全国普通高校学科竞赛排行榜&rdquo;。大赛紧密围绕当前社会急需的信息技术专业重点领域，着力培养高校大学生的专业IT技能和创新实践能力，是高等教育教学改革和创新人才培养的重要竞赛项目，是以赛促学、以赛促教的大学生科技创新的重要平台。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">本次优异成绩的取得，展现了我校学生优秀的专业素养、心理素质、拼搏精神和创新能力。通过此次赛事，我校师生将认真总结参赛经验，继续抓好以赛促学、以赛促教、以赛促改，进一步完善人才培养模式。</span></p>');
INSERT INTO content
                    VALUES (206, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">3月7日，我校在行政楼一楼会议室召开了2024-2025学年第二学期第二次教学工作例会。会议由副校长傅志军主持，教务处、质量监测与评估中心负责人及部门相关人员，各教学院（部）院长（主任）、教学副院长（副主任）、教务科长等相关负责人参加了会议。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-14%2019%3A51%3A58%E5%9B%BE%E7%89%871.png?Expires=2059991518&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=GwBPkCjY8tipNpX%2Bc%2F%2FEefn7QDA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-14%2019%3A51%3A58%E5%9B%BE%E7%89%871.png?Expires=2059991518&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=GwBPkCjY8tipNpX%2Bc%2F%2FEefn7QDA%3D" alt="" width="650" height="413" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">会议听取了校督导组组长黄承烈对开学以来教学督查情况的汇报。从督查情况来看，整体教学情况正常，但仍存在一些问题，需进一步改进。评建办主任何习平随后布置了本学期实践教学专项检查工作，详细说明了检查目标、内容及具体要求，强调需通过专项检查强化实践教学质量，突出专业特色。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">教务处副处长王金林对近期的教学与管理工作进行了布置安排。针对2025届本科生毕业论文（设计）及岗位实习，要求各学院严格把控进度与质量；同步推进第二批&ldquo;十四五&rdquo;职业教育国家规划教材申报工作，确保我校推荐的教材按时完成系统填报。课程思政示范课程申报工作须于3月28日前完成，各学院需积极组织推荐。此外，已获学士学位授权专业需再次梳理专业建设材料，做好质量评估准备。各学院需高度重视年检迎检工作，严抓教风学风建设，加强新入职教师培训指导，并动员师生积极参与教学成果奖申报。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">副校长傅志军提出了三点要求：一是解放思想、转变观念，主动适应职业教育发展新形势，不断加强自我学习和管理，提升教学管理水平。二是要求全体人员要借智、借力、借道，实干、苦干、巧干，强化实践教学，加强校企合作，共建专业课程、教材和实训基地，做好实验（训）指导书编写工作，突出专业特色。三是扎实推进具体工作，包括：要强化学风教风建设，落实学生晨读、晚自习制度，做好师生&ldquo;六带&rdquo;&ldquo;三带&rdquo;工作，严格教学监督，确保教师按时到岗、认真授课；要定期组织活动，深入研究教学方法，要动员师生积极参与各类竞赛，提升获奖数量与质量；要重点做好新增7个本科专业及2个专科专业的人才培养方案制定，统一专业基础课程模块，增设技能训练课程。</span></p>');
INSERT INTO content
                    VALUES (207, '<p>Hello, World!</p>');
INSERT INTO content
                    VALUES (208, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">12月13日上午，我校召开了2024年度学士学位授权专业质量评估评审会，副校长傅志军出席会议并讲话。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">评审会邀请了南昌航空大学舒坚教授、华东交通大学虚拟现实（VR）产业学院院长肖美华教授、江西师范大学教育教学评估中心揭安全教授、江西农业大学计算机与信息工程学院院长王映龙教授、南昌工程学院教务处处长谢云敏教授等5位专家，对我校大数据工程技术、导航工程技术与网络与新媒体技术等三个专业开展学士学位授权质量评审工作。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A10%3A09%E5%9B%BE%E7%89%876.png?Expires=2049714610&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=itnSedS3ukfkhJUXudwDCXBA%2F7g%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A10%3A09%E5%9B%BE%E7%89%876.png?Expires=2049714610&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=itnSedS3ukfkhJUXudwDCXBA%2F7g%3D" alt="" width="650" height="401" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">傅志军代表学校对专家组一行的到来表示欢迎和感谢，向专家组介绍了我校办学历史、学科设置、师资力量、人才培养等基本情况。他表示，此次学士学位授权专业质量评审工作是对我校参评专业的一次全面检验，更是对我们未来发展的重要支持和鞭策，对提升我校本科专业建设水平和人才培养质量具有重要意义，期望各位专家能够提出宝贵的意见和建议，推动专业质量持续提升。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">随后，三个参评专业负责人分别向专家组作专业质量自评情况汇报。专家组通过深度访谈、资料审查等多种方式，全面了解各专业的建设状况。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">反馈会上，专家依次对三个参评专业进行了细致全面的反馈，对我校各专业的建设成效给予肯定，并就各专业的培养目标与社会需求紧密度、课程体系优化、课程内容时代前沿性、基础课程设计紧密围绕专业需求、实践教学注重技术技能的培养、加强校企合作促进产教融合、提升学生的实际操作能力等方面给出了指导性的意见和建议。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">傅志军对此次会议进行了总结，他指出，此次评审会邀请到的专家点评精准而专业，不仅是对我校专业建设水平的客观评价，更为将来专业建设发展提供了极具价值的指引。相关学院要认真梳理专家的评审意见和建议，由院长牵头制定切实可行的整改措施，紧紧围绕高层次技术技能人才培养的核心目标，加强教师队伍建设，建设好质量保障体系，积极探索产教融合的新模式，不断强化专业的内涵建设，努力打造具有鲜明特色和竞争优势的专业品牌。</span></p>');
INSERT INTO content
                    VALUES (209, '<p style="margin-bottom: 0pt; margin-left: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑;"><span style="font-size: 16pt;">为</span><span style="font-size: 16pt;">推动我校教学与管理工作高质量发展</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">5</span><span style="font-size: 16pt;">月</span><span style="font-size: 16pt;">6</span><span style="font-size: 16pt;">日下午，我校在行政楼一楼会议室召开了2023-2024学年第二学期第</span><span style="font-size: 16pt;">三</span><span style="font-size: 16pt;">次教学工作</span><span style="font-size: 16pt;">例会</span><span style="font-size: 16pt;">。</span><span style="font-size: 16pt;">执行校长</span><span style="font-size: 16pt;">范红铭</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">教务处</span><span style="font-size: 16pt;">、</span><span style="font-size: 16pt;">科技处、人事处、学工处、质评中心、财务处、信息处、实验实训中心、校企合作办、图书馆等主要负责人，各教学院（部）院长（主任）、教学副院长（副主任）、教务科长及教务处人员等</span><span style="font-size: 16pt;">参加了会议。</span><span style="font-size: 16pt;">傅志军</span><span style="font-size: 16pt;">副</span><span style="font-size: 16pt;">校长主持会议并讲话。</span></span></p>
<p style="margin-bottom: 0pt; margin-left: 0pt; text-indent: 32pt; line-height: 24pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 16pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241216/675fdb99b760ba23a2900aea.png" /></span></p>
<p class="17" style="margin-left: 0.0000pt; text-indent: 32.0000pt; text-autospace: none; text-align: justify; text-justify: inter-ideograph; line-height: 26.0000pt;" align="justify">&nbsp;</p>
<p class="17" style="margin-left: 0.0000pt; text-indent: 32.0000pt; text-autospace: none; text-align: justify; text-justify: inter-ideograph; line-height: 26.0000pt;" align="justify"><span style="font-family: 微软雅黑;"><span style="font-size: 16pt;">教务处处长李嵩就4月份的</span><span style="font-size: 16pt;">工作进行了</span><span style="font-size: 16pt;">总结</span><span style="font-size: 16pt;">汇报</span><span style="font-size: 16pt;">，并对5月份各项教学工作进行了布置安排。图书馆负责人刘慎河</span><span style="font-size: 16pt;">就</span><span style="font-size: 16pt;">省文明办、省教育厅举办的第八届&ldquo;书香伴成长&rdquo;读书活动的具体安排进行了布置。</span></span></p>
<p style="margin-bottom: 0pt; margin-left: 0pt; text-indent: 32pt; text-align: justify; line-height: 26pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑;"><span style="font-size: 16pt;">执行校长范红铭在会上强调，要将教学与管理工作摆在学校高质量发展的突出位置，明确好教学基本定位。一是对标本科教学工作合格评估标准的要求，严格规范管理。全面了解评估要求</span><span style="font-size: 16pt;">，教学与管理工作要紧紧围绕标准要求展开，不断加强师资队伍建设，提升教师教学水平，鼓励教师多参加含金量高的赛事，争取重点突破。完善教学资源配置，加强教学基础设施建设，规范教学管理，加强质量保障体系建设。</span></span></p>
<p style="margin-bottom: 0pt; margin-left: 0pt; text-indent: 32pt; text-align: justify; line-height: 26pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑;"><span style="font-size: 16pt;">二是狠抓内涵建设，注重质量提升。</span><span style="font-size: 16pt;">在专业建设方面，各学院要提前布局谋划，以市场需求为导向，结合学科发展趋势，不断优化专业结构，做好新专业的申报和建设工作。</span><span style="font-size: 16pt;">课程建设是提升教学质量的关键环节</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">要不断</span><span style="font-size: 16pt;">加强课程建设，完善课程体系，更新教学内容和教学方法。积极与企业开展合作，共同建设实践教学基地，为学生提供更多的实践机会。还</span><span style="font-size: 16pt;">要</span><span style="font-size: 16pt;">加强与企业的沟通和交流</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">了解企业的需求和反馈，为教学改革提供依据和方向</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">提高人才竞争力。重视校园文化建设，贯彻落实好&ldquo;十一工程&rdquo;。</span></span></p>
<p style="margin-bottom: 0pt; margin-left: 0pt; text-indent: 32pt; text-align: justify; line-height: 26pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 微软雅黑; font-size: 16pt;">三是加强教学工作沟通协调。职能部门应主动与二级学院保持密切联系，了解他们的需求和困难，及时提供帮助和支持。同时，二级学院也应积极参与学校的政策讨论和规划制定，为学校的发展出谋划策；学院与学院间要加强交流互鉴，在教学资源、科研项目等方面进行合作，分享先进经验，共同提升学校的整体实力；教师与学生要形成良性互动，教师应倾听学生的想法和意见，尊重他们的个性和差异，建立良好的师生关系。</span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 24pt; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 微软雅黑;"><span style="font-size: 16pt;">傅校长强调，教学与管理工作要讲规范、重质量、重创新。</span><span style="font-size: 16pt;">一是重视实验实训，优化课程成绩评定方式，加大实验实训成绩占比。二是认真落实好期中教学检查，做好基础性工作，形成规范化常态化。三是根据社会需求和学科发展趋势，及时修订人才培养方案。在修订过程中，注重培养学生的实践能力和创新思维，增加实验实训环节的比重，还要注重培养学生的综合素质和人文素养，加强通识教育和选修课程的设置。四是做好毕业论文（设计）工作，全过程严格把关，充分运用好考研成功资源，积极开展考研经验分享活动。五是高度重视教学成果奖，要提高站位，进行宏观设计，在总结过去挖掘有用素材的基础上，进行理论升华，下功夫打磨实力。</span></span></p>');
INSERT INTO content
                    VALUES (210, '<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">1</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">月</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">2</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">日，学校期末考试统考正式开考。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校党委书记、督导专员</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">饶勇，党委副书记、</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">执行校长范红铭，副校长</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">傅志军带领有关部门</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">负��人，深入一线开展期末考试巡考工作</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">巡考过程中，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">饶勇</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">、范红铭、</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">傅志军等</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">全面检查考场环境、考试安排、考试秩序、监考教师履职和学生考风考纪等情况，并与考务人员深入交流，全面了解考试具体情况。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A30%3A48%E5%9B%BE%E7%89%871.png?Expires=2051263848&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RlLrsnSRvcTCZHZwU9ZIpyfsJ98%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 453px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A30%3A48%E5%9B%BE%E7%89%871.png?Expires=2051263848&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RlLrsnSRvcTCZHZwU9ZIpyfsJ98%3D" alt="" width="650" height="453" /></a></span></span></p>
