<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #23527c; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; outline-width: 0px; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A28%E5%9B%BE%E7%89%873.png?Expires=2051263889&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R%2FmAe%2BI2B1Bl5wGH2lSh4EHjV1E%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 433px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A28%E5%9B%BE%E7%89%873.png?Expires=2051263889&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R%2FmAe%2BI2B1Bl5wGH2lSh4EHjV1E%3D" alt="" width="650" height="433" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">期末考试不仅是检验教学质量的重要环节，更是展现学风、考风、校风的重要窗口。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校领导要求</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">切实做好相关工作，严肃考场纪律，把考风考纪建设贯穿到人才培养全过程。各学院要按照学校工作要求参与巡考工作。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff;">从检查情况看，期末考试考场安排规范有序，监考教师认真履行监考职责，学生自觉遵守考场纪律，严肃考风考纪成效明显。</span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff;">我校始终坚持校领导期末考试巡考制度，高度重视考试工作，不断优化考务管理，致力于为学生营造公平、公正、良好的考试环境，确保期末考试工作顺利完成。</span></p>');
INSERT INTO content
                    VALUES (211, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">近日，2024年江西省教学成果奖青年培育项目评选结果</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">公布</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">，我校网络工程学院申报的《党建引领、产教协同，职业本科网络类专业</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">&ldquo;四对接&ldquo;人才培养创新与实践</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">》和VR与艺术学院申报的《&ldquo;一体设计、双向迭代、三线贯通&rdquo;环境艺</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">术设计专业课程教学改革创新与实践</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">》两个项目成功入选</span>。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2051454705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=eE1HCQDIELW25gN4bf0hQPpYPNo%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 427px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2051454705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=eE1HCQDIELW25gN4bf0hQPpYPNo%3D" alt="" width="650" height="427" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A58%E5%9B%BE%E7%89%872.png?Expires=2051454718&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=OPhzbZiBMnr2Jq2kln5mxsORpjM%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 298px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A58%E5%9B%BE%E7%89%872.png?Expires=2051454718&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=OPhzbZiBMnr2Jq2kln5mxsORpjM%3D" alt="" width="650" height="298" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000;">据悉，本次申报项目经省教育厅组织专家评审、会议研究，拟立项江西省教学成果奖青年培育项目（职业教育类项目）167项。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">此次入选充分展现了近年来我校在推进教育教学改革、优化专业建设以及创新人才培养模式等方面所取得的阶段性成果。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">这</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">不仅是对</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">我</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">校教育教学改革成果的肯定，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">也</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">是对青年教师团队辛勤付出的认可。学校将进一步加大对青年教师的培养和支持力度，不断加大教育教学研究和改革力度，推动学校教育教学水平再上新台阶</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">。</span></span></p>');
INSERT INTO content
                    VALUES (212, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;">2月17日，我校迎来2025年春季学期开学首日。校党委书记、督导专员饶勇，党委副书记、执行校长范红铭带领全校各级领导干部共计71人深入教学一线，与师生共同开启新学期课堂教学序幕，覆盖软件工程学院等9个二级学院、 43个本专科专业、64个教学班级，通过&ldquo;零距离&rdquo;观察课堂教学，为新学期教育教学工作开好局、起好步。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;">按照学校&ldquo;春季开学安全教育周&rdquo;统一部署，教师��首先开展消防安全主题教育，通过观看警示教育片、师生共话消防安全重要性，将安全意识和责任深植学生心中。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2055234705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R3LV1FYS4OESli9hz4JWzJMaPb0%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2055234705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R3LV1FYS4OESli9hz4JWzJMaPb0%3D" alt="" width="650" height="434" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;">消防安全教育结束后，教师们根据教学计划，有序开展专业课程和基础课程的教学活动，在简要介绍课程目标、学习要求及考核方式后，正式开启新学期第一讲。学生们以饱满的精神状态投入学习，课堂上专注聆听、踊跃发问。各级领导重点关注&ldquo;师生双主体&rdquo;互动成效，对教师良好的职业素养和精准对接职业能力需求的教学设计，以及学生展现出的积极向上的求知欲望和主动学习的态度给予肯定。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A32%3A08%E5%9B%BE%E7%89%872.png?Expires=2055234729&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=FkJaLUnoMqD7IGixYbKJnogP%2BWw%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A32%3A08%E5%9B%BE%E7%89%872.png?Expires=2055234729&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=FkJaLUnoMqD7IGixYbKJnogP%2BWw%3D" alt="" width="650" height="434" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A32%3A27%E5%9B%BE%E7%89%873.png?Expires=2055234748&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Ifb1oswOdhCHOqbXNkCI1lnsH%2Bs%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-18%2018%3A32%3A27%E5%9B%BE%E7%89%873.png?Expires=2055234748&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=Ifb1oswOdhCHOqbXNkCI1lnsH%2Bs%3D" alt="" width="650" height="433" /></a></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: 等线; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 12pt; font-family: 宋体; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 21.6px; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">新学期伊始的教学听课活动，既是对寒假教学备课成效的集中检阅，更是向&ldquo;课堂革命&rdquo;发出的冲锋号角。学校将进一步强化&ldquo;以学生发展为中心&rdquo;的理念，持续完善教育教学评价与反馈机制，推动教学从&ldquo;知识传授&rdquo;向&ldquo;能力塑造&rdquo;转型，不断提升人才培养质量。</span></span></p>');
INSERT INTO content
                    VALUES (213, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">8月28日上午，我校在行政楼一楼会议室通过线上方式与圣何塞大学成功召开了&ldquo;创新思维与国际教育融合&rdquo;专题研讨会，此次会议邀请了国内外教育专家、学者参加。我校校长庄力可博士、USJ创校校长Claude Wang博士、美国教育专家Head of School联合总校校长Olaf Jorgenson博士以及USJ特聘教授艾欣博士，共同探讨在全球化背景下，如何通过创新思维推动国际教育的深入发展，培养具有国际竞争力的复合型人才。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-01%2010%3A09%3A3941807ac93c7014c3d5cc51a37ee05a48.png?Expires=2040516580&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=UANYuDocDlfUep8JVnyiiJ8XKIs%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-01%2010%3A09%3A3941807ac93c7014c3d5cc51a37ee05a48.png?Expires=2040516580&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=UANYuDocDlfUep8JVnyiiJ8XKIs%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">会议上，党委副书记、执行校长范红铭主持会议并致欢迎辞，他表示，在全球化日益加深的今天，高校作为知识传播与创新的重要基地，必须积极拥抱变化，将创新思维融入国际教育的每一个环节，以应对未来社会的挑战，并希望本次研讨会能够成为大家交流思想、分享智慧、共谋发展的平台，���发出更多推动教育创新发展的灵感与火花。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">随后，Claude Wang博士、庄力可博士、Olaf Jorgenson博士发表了精彩的主旨演讲，他们结合自身经验和研究成果，强调了面对全球化的挑战与机遇，创新思维在国际教育中的应用和可行性，在&ldquo;创新思维+&rdquo;的引领下，深入培养学生的批判性思维、创新能力和社会责任感，为他们未来的职业发展和社会贡献奠定坚实的基础，学习借助先进科技手段，如人工智能、虚拟现实等，实现教学内容的个性化、教学方法的创新化以及学习方式的灵活化。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-01%2010%3A10%3A246fbd21e17eb55fe6c07fb2191c7b6777.jpg?Expires=2040516624&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KNM0yPBnqBHgEHibfw36zD61pcw%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-01%2010%3A10%3A246fbd21e17eb55fe6c07fb2191c7b6777.jpg?Expires=2040516624&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KNM0yPBnqBHgEHibfw36zD61pcw%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">USJ特聘教授艾欣博士是一位&ldquo;创新设计思维&rdquo;的先行者，从事创新设计思维培训多年，拥有丰富的创新教育经验，曾为国内外公司、机构、大学等9000多人提供创新培训和顾问服务。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">艾欣博士围绕&ldquo;Design Thinking+ for Future Education&rdquo;主题深入剖析&ldquo;设计思维+&rdquo;的内涵与实践路径。她通过生动的案例，展示了创新设计思维在各行业中的应用与探索，并从&ldquo;什么是设计思维&rdquo;&ldquo;怎么学习设计思维&rdquo;两个方面全面地诠释了这一理念的多样性和普遍性，<strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">同时提出设计思维的学习规则即三个原则（空杯心态、延迟评判、为错误而欢呼）和一个基本点（保持快乐）</strong>，并设置分组讨论环节，让与会者更加深入地体会到设计思维的趣味性和可操作性。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">在互动问答环节，与会者根据各自的研究领域和兴趣点，积极向演讲嘉宾提问，共同探讨教育创新中的难点和热点问题。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">此次研讨会让大家受益匪浅，不仅加深了对创新思维与国际教育融合的理解和认识，也为未来的教育创新实践提供了宝贵的思路和方向</strong><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">。</strong>同时，也期待在未来的日子里能够继续加强交流与合作，以&ldquo;创新思维+&rdquo;为引领，共同推动国际教育的繁荣与发展，为培养更多具有全球视野、创新精神和实践能力的人才贡献智慧和力量。</span></p>');
INSERT INTO content
                    VALUES (214, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 30pt;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">2025年全国硕士研究生招生考试录取工作落下帷幕，我校学生凭借不懈的努力奋斗，共有85名学生成功考入心仪学府，录取院校涵盖宁波大学、长安大学、宁夏大学、东北林业大学、昆士兰大学等53所国内外高校。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 30pt;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A18image.png?Expires=2062653018&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=i9fWyPB6VI6NWNSbohdsE1JxpME%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A18image.png?Expires=2062653018&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=i9fWyPB6VI6NWNSbohdsE1JxpME%3D" width="650" /></a></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A30image.png?Expires=2062653031&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=riUNjrhdOETqQVWoMDlhkPx2DDs%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A30image.png?Expires=2062653031&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=riUNjrhdOETqQVWoMDlhkPx2DDs%3D" width="650" /></a></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A41image.png?Expires=2062653041&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=TlW9OuFrfmkrJ0ggn%2B66AYhRVFw%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A10%3A41image.png?Expires=2062653041&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=TlW9OuFrfmkrJ0ggn%2B66AYhRVFw%3D" width="650" /></a></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A11%3A08image.png?Expires=2062653069&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=s4bFTkxXX2FMmj6Ny6t%2FrKDLM8I%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A11%3A08image.png?Expires=2062653069&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=s4bFTkxXX2FMmj6Ny6t%2FrKDLM8I%3D" width="650" /></a></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 28px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A11%3A18image.png?Expires=2062653078&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=epYLzvF4EVUK6oUpsWcdz8C7L4Q%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-15%2015%3A11%3A18image.png?Expires=2062653078&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=epYLzvF4EVUK6oUpsWcdz8C7L4Q%3D" width="650" /></a></p>
<p style="box-sizing: border-box; margin: 0px 1px 0px 6pt; padding: 0px; border-width: 0px; font-size: 15pt; font-family: 仿宋; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 40px; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 15pt; font-family: 仿宋; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">&nbsp;</span></p>');
INSERT INTO content
                    VALUES (215, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 24px; color: black;">2025年2月11日，学校召开2024年度民办高校年检工作会议。全体校领导、中层以上干部参加会议。党委副书记、执行校长范红铭主持会议。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 24px; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-11%2017%3A32%3A55%E5%9B%BE%E7%89%871.png?Expires=2054626375&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=e%2BM9kWdxxz71Lma0L78kz0Or2uw%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-02-11%2017%3A32%3A55%E5%9B%BE%E7%89%871.png?Expires=2054626375&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=e%2BM9kWdxxz71Lma0L78kz0Or2uw%3D" alt="" width="650" height="487" /></a></span></p>
<p style="text-indent: 2em; text-align: justify;" align="justify">&nbsp;</p>
<p style="text-indent: 2em; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">会上，执行校长范红铭强调，民办高校年检工作是关乎学校生存发展的全局性工作，既是对办学质量的全面考核，也是推动内涵建设的重要契机。年检结果将直接影响招生计划、财政资金分配和评优资格，全校必须站在战略高度统一认识，以问题为导向系统梳理短板，通过查漏补缺强化内部管理、规范依法治校，为学校可持续发展奠定基础。</span></p>
<p style="text-indent: 2em; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">为此，他提出三方面核心要求：一是提高政治站位，校领导班子需统筹全局、压实责任，确保理事会与党委会目标落地；各部门须深入学习民办教育法规政策，严格对照《2024年度民办高校年检工作实施方案》及指标体系开展自查自评，精准准备数据和佐证材料。二是聚焦精准发力，主动对接省教育厅评价处室掌握考核动态，深入研读指标内涵与释义，确保理解&ldquo;准、精、全&rdquo;；专家现场核查环节要突出&ldquo;细、优、实&rdquo;，通过任务分工责任制确保每项指标专人跟进、材料完备。三是强化组织保障，严明纪律要求全校上下服从指挥、协同攻坚，杜绝推诿扯皮，对履职不力者严肃问责，以高标准凝聚合力完成迎检任务。</span></p>
<p style="text-indent: 2em; text-align: justify;" align="justify"><span style="font-family: 微软雅黑; font-size: 14px;">他总结指出，年检既是挑战更是机遇，需将迎检准备与日常管理深度融合，通过规范化、系统化整改推动办学水平全面提升。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 24px; color: black;">此次会议的召开，不仅为我校2024年度民办高校年检工作指明了方向，更为学校的健康发展注入了新的动力。全校师生将以此为契机，继续努力，共同书写学校发展的新篇章。</span></p>');
INSERT INTO content
                    VALUES (216, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">近日，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">江西省高等教育学会实验室工作分会印发《关于表彰2024年江西省高校实验室与资产管理工作先进单位、团队、个人及突出贡献奖获得者的通知》（赣实发〔2024〕11号），我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">荣获</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">2024年江西省高校实验室与资产管理工作</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">先进团队</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">&rdquo;，实验实训管理中心</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">帅金凤</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">老师获&ldquo;先进个人&rdquo;。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A40%E5%9B%BE%E7%89%873.png?Expires=2049714401&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R2K7j8hg9ZXDguqQWBFWNHMvB0g%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A40%E5%9B%BE%E7%89%873.png?Expires=2049714401&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R2K7j8hg9ZXDguqQWBFWNHMvB0g%3D" alt="" width="650" height="800" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A58%E5%9B%BE%E7%89%874.png?Expires=2049714419&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HhsV7C%2FAglmnOUPfXhSK%2Byez4hY%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A58%E5%9B%BE%E7%89%874.png?Expires=2049714419&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HhsV7C%2FAglmnOUPfXhSK%2Byez4hY%3D" alt="" width="650" height="669" /></a><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A07%3A13%E5%9B%BE%E7%89%875.png?Expires=2049714433&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=YAfr40bwHSK7XFSfj2avd2DjwOQ%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A07%3A13%E5%9B%BE%E7%89%875.png?Expires=2049714433&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=YAfr40bwHSK7XFSfj2avd2DjwOQ%3D" alt="" width="650" height="374" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">据悉，此次</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">评选出我省高校2024年实验室与资产管理工作&ldquo;先进单位&rdquo;22个、&ldquo;先进团队&rdquo;38个、&ldquo;先进个人&rdquo;63人。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">近年来，我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实验实训管理中心</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">不断深化内部管理改革，强化资源优化配置，推动实验室安全建设与教学质量并进。持续改善实验室教学环境，为师生创造更加安全、高效、便捷的</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实训</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">教学环境。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">此次获奖是对学</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实验（训）室工作的肯定，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">将以此为契机，进一步做好实验（训）室建设规划，优化资源配置，强化团队建设，不断发挥实验（训）室安全育人作用，助推</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">学校职业教育事业</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">高质量发展。</span></span></p>');
INSERT INTO content
                    VALUES (217, '<p class="15" style="text-indent: 30.0000pt; punctuation-trim: leading; text-autospace: ideograph-numeric; text-align: justify; text-justify: inter-ideograph; line-height: 25.0000pt; margin: 0.0000pt;" align="justify"><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><span style="font-family: 仿宋;">为弘扬工匠精神，充分发挥职业技能竞赛在培养学生专业实践能力的作用，提升技��技能人才培养质量，我校于</span><span style="font-family: 仿宋;">2024年4月至5月组织开展了第十届职业技能大比武，经审核，本届职业技能大比武共363名学生获奖，其中罗永康等68名同学获一等奖，郭文锋等116名同学获二等奖，张思怡等179名同学获三等奖，邹林薏等37名老师获优秀指导老师奖。</span></span></p>
<p class="15" style="text-indent: 24pt; line-height: 25pt; margin: 0pt;" align="justify"><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241226/676cd1cab760ba23a2900aeb.png" /><br /></span></p>
<p class="15" style="text-indent: 30.0000pt; punctuation-trim: leading; text-autospace: ideograph-numeric; text-align: justify; text-justify: inter-ideograph; line-height: 25.0000pt; margin: 0.0000pt;" align="justify"><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><span style="font-family: 仿宋;">本次职业技能大比武参照了江西省职业院校职业技能大赛和江西省大学生科技创新与技能大赛的要求，体现了专业的核心技术技能，展示了���生的综合职业技能。大赛</span></span><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><span style="font-family: 仿宋;">设区块链应用操作竞赛、大数据技术与应用技能竞赛、程序设计竞赛、虚拟现实</span><span style="font-family: 仿宋;">(VR)交互开发技能竞赛等27个技能竞赛，</span></span><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><span style="font-family: 仿宋;">比赛项目丰富，专业性强。</span></span><span style="font-family: 仿宋; font-weight: normal; font-style: normal; font-size: 15.0000pt; background: #ffffff;"><span style="font-family: 仿宋;">希望同学们再接再厉，在各类竞赛中展示江软学子</span><span style="font-family: 仿宋;">&ldquo;学好软件，报效祖国&rdquo;和&ldquo;学技能、勇争先&rdquo;的精神风貌。</span></span></p>');
INSERT INTO content
                    VALUES (218, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="center"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">&nbsp;</strong></span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">5月24日，2024-2025年华为ICT大赛2024-2025全球总决赛闭幕式暨颁奖典礼在深圳举行，我校网络工程学院代表队从全球21万余名参赛者中脱颖而出，斩获<strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">实践赛网络赛道全球三等奖。</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">&nbsp;</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff;" align="center"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-30%2010%3A14%3A55%E5%9B%BE%E7%89%8712.png?Expires=2063931295&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=WnqDs3RShTWuGBXE0qBAaL04XFk%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-30%2010%3A14%3A55%E5%9B%BE%E7%89%8712.png?Expires=2063931295&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=WnqDs3RShTWuGBXE0qBAaL04XFk%3D" alt="" width="650" height="487" /></a>&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">此次获奖不仅是学校深化产教融合的重要里程碑，更是&ldquo;岗课赛证&rdquo;融通育人体系的生动实践。作为江西省首批开展华为ICT学院建设的高校，我校通过与华为共建&ldquo;双师型&rdquo;教学团队、联合开发行业认证课程，将企业真实项目融入专业教学，构建起&ldquo;岗位需求-课程体系-技能竞赛-职业认证&rdquo;四位一体的人才培养闭环。其中，网络工程学院超80%专业核心课程实现教学标准与行业标准、教学内容与岗位需求、教学过程与生产流程对接。将ICT行业最新技术标准转化为教学资源库，近三年已培养出数十名获得HCIE认证的尖端人才。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">该学院将华为认证知识点转化为教学案例，通过&ldquo;项目驱动、实境训练&rdquo;的教学模式，使学生在备赛过程中同步完成企业级项目实践，实现&ldquo;毕业即上岗，上岗即骨干&rdquo;的人才培养目标。近三年，毕业生在华为HCIE认证通过率、华为生态企业录用率等关键指标上领跑江西省同类院校。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">学校将持续深化产教融合、赛教融合改革，通过&ldquo;产业引领、标准对接、实战育人&rdquo;的创新模式，提升学校服务区域现代化产业体系建设和经济社会发展贡献能力和贡献率，培养更多具有国际视野的&ldquo;数智工匠&rdquo;。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">&nbsp;</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #23527c; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; outline-width: 0px; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-30%2010%3A15%3A15%E5%9B%BE%E7%89%8713.png?Expires=2063931316&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=o0Yq1%2FELDNyH75CmBYuUcztxPnc%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-30%2010%3A15%3A15%E5%9B%BE%E7%89%8713.png?Expires=2063931316&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=o0Yq1%2FELDNyH75CmBYuUcztxPnc%3D" alt="" width="650" height="866" /></a></span></p>');
INSERT INTO content
                    VALUES (219, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">5月24日，江西省职业教育学会艺术专业委员会(以下简称艺委会)重点工作部署会暨江西省职业教育学会艺术专业委员会红色文化创作基地揭牌仪式在江西软件大学井冈山校区召开。江西省职业教育学会艺委会主任单位和副主任单位、相关院校及企业单位的代表参加。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A36%3A28%E5%9B%BE%E7%89%871.png?Expires=2063842589&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=REi9f8gYMIvmgRutdm5eywbJu9I%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A36%3A28%E5%9B%BE%E7%89%871.png?Expires=2063842589&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=REi9f8gYMIvmgRutdm5eywbJu9I%3D" width="650" height="487" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">上午，艺委会相关人员参观江西软件大学井冈山校区《红色文化师生获奖作品展》，艺委会召开了副主任以上委员工作会。会议讨论并通过艺委会各工作部部长、副部长人选及各专业工作部的工作职责及主要工作计划。同时，会上讨论通过职业院校师生作品设计大赛方案及走访名校名企工作方案。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: center; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A37%3A06%E5%9B%BE%E7%89%872.png?Expires=2063842627&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=dnaA7PO1IJG6yVHYdtJMQzQRsYA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1);" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A37%3A06%E5%9B%BE%E7%89%872.png?Expires=2063842627&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=dnaA7PO1IJG6yVHYdtJMQzQRsYA%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">下午进行了&ldquo;红色文化创作基地&rdquo;揭牌仪式及产品设计工作部成立大会。会上，井冈山市人民政府副市长刘济光对各位领导、专家的到来表示欢迎。他指出在这片红色沃土上搭建红色文化创作基地，就是要以职业教育的创新实践为笔，以艺术创作的独特语言为墨，在新时代续写红色文化传承的新篇章。希望以此次基地揭牌为起点，携手在这片充满希望的土地上，用画笔勾勒初心，用创意激活传统，用匠心培育人才，让井冈山精神在艺术的诠释中历久弥新，让职业教育在红色的浸润中根深叶茂！</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A38%3A00%E5%9B%BE%E7%89%873.png?Expires=2063842680&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=EPoY%2BCI6u4dTlTr7pYw207r%2Fk78%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-05-29%2009%3A38%3A00%E5%9B%BE%E7%89%873.png?Expires=2063842680&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=EPoY%2BCI6u4dTlTr7pYw207r%2Fk78%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">江西软件大学井冈山校区管委会副主任于涛介绍了学校建设情况和所获荣誉。自2022年4月承接首次写生业务以来累计完成1500余名学生写生活动，形成&ldquo;红色文化+艺术创作+数字技术&rdquo;的特色实践模式。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">江西软件大学VR与艺术学院副院长、江西省职业教育学会艺委会副主任帅茨平介绍了红色文化创作基地基本情况。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
