INSERT INTO content
                    VALUES (243, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">在第四十个教师节来临之际，为弘扬尊师重教的优良传统，增强新进青年教师的责任感和使命感，9月9日下午，我校在行政楼一楼会议室举行了青年教师座谈会。党委副书记、执行校长范红铭，教务处、人事处、科技处、后勤保障处等职能部门负责人及20余名青年教师代表参加了会议。傅志军副校长主持会议并讲话。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-12%2016%3A20%3A33image.png?Expires=2041489233&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KsSdq2mRXnrqqr1kEueztNBAsLA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-09-12%2016%3A20%3A33image.png?Expires=2041489233&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=KsSdq2mRXnrqqr1kEueztNBAsLA%3D" width="650" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">执行校长范红铭向全体新进青年教师表达了热烈的欢迎和衷心的祝贺。他指出，青年教师是学校发展的生力军，要高度重视青年教师的培养工作，提升教师的工作积极性和幸福感。学校职能部门要增强服务意识，以师为尊，坚定支持青年教师成长与发展。他强调，青年教师肩负着培养社会主义建设者和接班人的重任，应始终坚持党的教育方针，坚定理想信念，落实立德树人的根本任务。最后，他希望全体青年教师能够牢记使命、不负重托，为建设���特色、有品质、 有情怀、有作为的高水平职业技术大学而努力。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">副校长傅志军对新进青年教师提出了三点殷切期望：一是坚守教育初心，担当育人使命；二是加强学习，提升综合素质，增强教书育人的能力；三是尽快适应角色的转换，发挥个人所长，做好教书育人工作，为学校发展做出贡献。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">教务处处长李嵩和后勤处处长谢文平发言，表示学校将持续关注青年教师的成长，提供必要的支持与保障，同时积极倾听青年教师的声音，解决他们在工作和生活中遇到的问题，共同营造一个和谐、积极的工作环境。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">新进青年教师代表先后发言，分享了他们加入学校以来的心路历程，表达了对学校的热爱以及对未来工作的期许。他们纷纷表示，作为高校教师队伍的新生力量，将以饱满的热情和坚定的信念投身到教育事业中，为学生的成长和学校的发展贡献自己的力量。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">本次座谈会的成功举办，不仅展现了我校对青年教师的重视，也彰显了学校致力于培养高素质教师队伍的决心。期待青年教师能够在学校的支持下，不断成长，为学校的未来发展注入新的活力。</span></p>');
INSERT INTO content
                    VALUES (244, '<p style="box-sizing: border-box; margin: 5pt 0pt; padding: 0px; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;">3月31日，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;">学校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;">隆重召开本科教学工作合格评估动员大会，全面部署迎评促建工作。学校执行理事长陈方平，校党委副书记、执行校长范红铭及全体在家领导出席会议，全校教职员工参加会议。会议由校务委员徐国荣主持。</span></span></p>
<p style="box-sizing: border-box; margin: 5pt 0pt; padding: 0px; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 5pt 0pt; padding: 0px; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-02%2012%3A58%3A0223.jpg?Expires=2058929883&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=4dhrVACuqbaVNrczicHPTHy3Els%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-04-02%2012%3A58%3A0223.jpg?Expires=2058929883&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=4dhrVACuqbaVNrczicHPTHy3Els%3D" width="650" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 5pt 0pt; padding: 0px; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: center; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="center"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; font-weight: bold; vertical-align: baseline; color: #404040; font-size: 18px;">高位部署，强化责任</span></strong></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;">校党委副书记、执行校长范红铭作动员讲话。他要求，各责任单位要认真学习评估指标体系，深刻理解内涵，对照指标全面开展自查，列出问题清单，剖析原因，结合学校实际提出改进措施，制订合理的评建工作规划。他强调，</span><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; font-weight: bold; vertical-align: baseline; color: #404040; font-size: 18px;">一是统一认识，深刻领会职本教学工作合格评估重要意义，适应新常态；二是全面自查，系统梳理职本教学工作合格评估工作任务，明确新方向；三是落实责任，协调形成职本教学工作合格评估工作合力，助推新发展。</span></strong><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #404040; font-size: 18px;">他号召，全校师生以&ldquo;主人翁&rdquo;姿态积极参与，形成&ldquo;人人关心评估、人人参与评估&rdquo;的良好氛围。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: center; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="center"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">凝心聚力，明确目标</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">校务委员傅志军对《江西软件职业技术大学本科教学工作合格评估建设工作方案》进行了详细解读，包括评估工作的总体要求、目标任务、责任分工及实施步骤。本科教学工作合格评估极其重要，其核心是围绕&ldquo;四个促进&rdquo;&ldquo;三个基本&rdquo; &ldquo;两个突出&rdquo;&ldquo;一个引导&rdquo;展开，大家要遵循&ldquo;以评促建、以评促改、以评促管、评建结合、重在建设&rdquo;20字方针，扎实推动各项工作落实落细。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: center; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="center"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;"><strong style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; font-weight: bold;">压实责任，立下&ldquo;军令状&rdquo;</strong></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">执行理事长陈方平与校党委副书记、执行校长范红铭，评建专项工作组代表郑重签署了《评建工作责任状》。此举旨在进一步夯实主体责任，清晰界定任务的关键时间节点。各责任单位将以责任状为指引，锚定任务节点，主动作为。各责任人深知责任重大，将带领团队紧锣密鼓推进评建工作，强化协作，确保各环节有序落实，全力迎接评估考验。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 18px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #333333;">职能部门人事处处长胡梅玲、学院院长代表韩士专教授、教师代表葛伟老师依次发言表态。</span></p>');
INSERT INTO content
                    VALUES (245, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">近日，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">江西省高等教育学会实验室工作分会印发《关于表彰2024年江西省高校实验室与资产管理工作先进单位、团队、个人及突出贡献奖获得者的通知》（赣实发〔2024〕11号），我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">荣获</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">2024年江西省高校实验室与资产管理工作</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">先进团队</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">&rdquo;，实验实训管理中心</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">帅金凤</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">老师获&ldquo;先进个人&rdquo;。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A40%E5%9B%BE%E7%89%873.png?Expires=2049714401&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R2K7j8hg9ZXDguqQWBFWNHMvB0g%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A40%E5%9B%BE%E7%89%873.png?Expires=2049714401&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R2K7j8hg9ZXDguqQWBFWNHMvB0g%3D" alt="" width="650" height="800" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A58%E5%9B%BE%E7%89%874.png?Expires=2049714419&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HhsV7C%2FAglmnOUPfXhSK%2Byez4hY%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A06%3A58%E5%9B%BE%E7%89%874.png?Expires=2049714419&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=HhsV7C%2FAglmnOUPfXhSK%2Byez4hY%3D" alt="" width="650" height="669" /></a><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A07%3A13%E5%9B%BE%E7%89%875.png?Expires=2049714433&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=YAfr40bwHSK7XFSfj2avd2DjwOQ%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A07%3A13%E5%9B%BE%E7%89%875.png?Expires=2049714433&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=YAfr40bwHSK7XFSfj2avd2DjwOQ%3D" alt="" width="650" height="374" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">据悉，此次</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">评选出我省高校2024年实验室与资产管理工作&ldquo;先进单位&rdquo;22个、&ldquo;先进团队&rdquo;38个、&ldquo;先进个人&rdquo;63人。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">近年来，我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实验实训管理中心</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">不断深化内部管理改革，强化资源优化配置，推动实验室安全建设与教学质量并进。持续改善实验室教学环境，为师生创造更加安全、高效、便捷的</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实训</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">教学环境。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">此次获奖是对学</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">实验（训）室工作的肯定，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">我校</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">将以此为契机，进一步做好实验（训）室建设规划，优化资源配置，强化团队建设，不断发挥实验（训）室安全育人作用，助推</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">学校职业教育事业</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">高质量发展。</span></span></p>');
INSERT INTO content
                    VALUES (246, '<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">12月13日上午，我校召开了2024年度学士学位授权专业质量评估评审会，副校长傅志军出席会议并讲话。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">评审会邀请了南昌航空大学舒坚教授、华东交通大学虚拟现实（VR）产业学院院长肖美华教授、江西师范大学教育教学评估中心揭安全教授、江西农业大学计算机与信息工程学院院长王映龙教授、南昌工程学院教务处处长谢云敏教授等5位专家，对我校大数据工程技术、导航工程技术与网络与新媒体技术等三个专业开展学士学位授权质量评审工作。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A10%3A09%E5%9B%BE%E7%89%876.png?Expires=2049714610&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=itnSedS3ukfkhJUXudwDCXBA%2F7g%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2024-12-16%2021%3A10%3A09%E5%9B%BE%E7%89%876.png?Expires=2049714610&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=itnSedS3ukfkhJUXudwDCXBA%2F7g%3D" alt="" width="650" height="401" /></a></span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">傅志军代表学校对专家组一行的到来表示欢迎和感谢，向专家组介绍了我校办学历史、学科设置、师资力量、人才培养等基本情况。他表示，此次学士学位授权专业质量评审工作是对我校参评专业的一次全面检验，更是对我们未来发展的重要支持和鞭策，对提升我校本科专业建设水平和人才培养质量具有重要意义，期望各位专家能够提出宝贵的意见和建议，推动专业质量持续提升。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">随后，三个参评专业负责人分别向专家组作专业质量自评情况汇报。专家组通过深度访谈、资料审查等多种方式，全面了解各专业的建设状况。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">反馈会上，专家依次对三个参评专业进行了细致全面的反馈，对我校各专业的建设成效给予肯定，并就各专业的培养目标与社会需求紧密度、课程体系优化、课程内容时代前沿性、基础课程设计紧密围绕专业需求、实践教学注重技术技能的培养、加强校企合作促进产教融合、提升学生的实际操作能力等方面给出了指导性的意见和建议。</span></p>
<p style="box-sizing: border-box; margin: 0px 1px; padding: 0px; border-width: 0px; font-size: 14px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;">傅志军对此次会议进行了总结，他指出，此次评审会邀请到的专家点评精准而专业，不仅是对我校专业建设水平的客观评价，更为将来专业建设发展提供了极具价值的指引。相关学院要认真梳理专家的评审意见和建议，由院长牵头制定切实可行的整改措施，紧紧围绕高层次技术技能人才培养的核心目标，加强教师队伍建设，建设好质量保障体系，积极探索产教融合的新模式，不断强化专业的内涵建设，努力打造具有鲜明特色和竞争优势的专业品牌。</span></p>');
INSERT INTO content
                    VALUES (247, '<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">1</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">月</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">2</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">日，学校期末考试统考正式开考。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校党委书记、督导专员</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">饶勇，党委副书记、</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">执行校长范红铭，副校长</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">傅志军带领有关部门</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">负��人，深入一线开展期末考试巡考工作</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">巡考过程中，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">饶勇</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">、范红铭、</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">傅志军等</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">全面检查考场环境、考试安排、考试秩序、监考教师履职和学生考风考纪等情况，并与考务人员深入交流，全面了解考试具体情况。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A30%3A48%E5%9B%BE%E7%89%871.png?Expires=2051263848&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RlLrsnSRvcTCZHZwU9ZIpyfsJ98%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 453px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A30%3A48%E5%9B%BE%E7%89%871.png?Expires=2051263848&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=RlLrsnSRvcTCZHZwU9ZIpyfsJ98%3D" alt="" width="650" height="453" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A05%E5%9B%BE%E7%89%872.png?Expires=2051263866&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=66mZWwTPMKDdif4O%2FFwtGek9H0M%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 433px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A05%E5%9B%BE%E7%89%872.png?Expires=2051263866&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=66mZWwTPMKDdif4O%2FFwtGek9H0M%3D" alt="" width="650" height="433" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;"><a style="box-sizing: border-box; color: #23527c; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; outline-width: 0px; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A28%E5%9B%BE%E7%89%873.png?Expires=2051263889&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R%2FmAe%2BI2B1Bl5wGH2lSh4EHjV1E%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 433px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2019%3A31%3A28%E5%9B%BE%E7%89%873.png?Expires=2051263889&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=R%2FmAe%2BI2B1Bl5wGH2lSh4EHjV1E%3D" alt="" width="650" height="433" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">期末考试不仅是检验教学质量的重要环节，更是展现学风、考风、校风的重要窗口。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">校领导要求</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff; font-size: 16px;">切实做好相关工作，严肃考场纪律，把考风考纪建设贯穿到人才培养全过程。各学院要按照学校工作要求参与巡考工作。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff;">从检查情况看，期末考试考场安排规范有序，监考教师认真履行监考职责，学生自觉遵守考场纪律，严肃考风考纪成效明显。</span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; background-color: #ffffff;">我校始终坚持校领导期末考试巡考制度，高度重视考试工作，不断优化考务管理，致力于为学生营造公平、公正、良好的考试环境，确保期末考试工作顺利完成。</span></p>');
INSERT INTO content
                    VALUES (248, '<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">近日，江西省教育厅公布了重点实验室立项</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">名单</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">软件工程学院、智能科技学院、北斗通航研究院联合</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">申报的&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">北斗通航与应用</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">重点实验室&rdquo;获批，成为我校首个</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">江西省教育厅</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">重点实验室。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&nbsp;这一成果标志着学校在科研创新与技术开发方面取得重要进展，进一步增强了学校在</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">北斗导航、无人机、云计算等</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">学科领域的科研实力，为学科平台建设注入了强劲动力。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A31%E5%9B%BE%E7%89%871.png?Expires=2051249611&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=0tbCHT6cA4EfnbWTjsMjzWAwWCc%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 350px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A31%E5%9B%BE%E7%89%871.png?Expires=2051249611&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=0tbCHT6cA4EfnbWTjsMjzWAwWCc%3D" alt="" width="650" height="350" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A49%E5%9B%BE%E7%89%872.png?Expires=2051249630&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9c2QpSe%2FRFJGyBFlQBeH1TpJetA%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 767px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-03%2015%3A33%3A49%E5%9B%BE%E7%89%872.png?Expires=2051249630&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=9c2QpSe%2FRFJGyBFlQBeH1TpJetA%3D" alt="" width="650" height="767" /></a></span></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">实验室将紧密对接江西省</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&ldquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">1269</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&rdquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">行动计划</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">和</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">&ldquo;江西省推进北斗产业发展若干措施&rdquo;</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">发展重大需求</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">突破无人机低空航路规划、云端综合管控和高精度定位等关键技术，为低空通航产业提供技术支持，并促进相关产业链的发展</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">研究成果将直接服务于无人机物流配送、农业遥感监测、应急救援等领域，为地方经济发展注入新动力。</span></span></p>
<p style="box-sizing: border-box; margin: 0pt; padding: 0pt; border-width: 0px; font-size: 12pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">实验室将加强与</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">有关</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">高校、科研机构及企业合作与交流</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">吸引优秀科研人员和学生参与研究工作，培养一批掌握前沿技术的专业人才，推动相关学科之间的交叉融合，探索新的教学模式，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">努力</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #323232; font-size: 16px;">成为省内领先、国内知名的科研平台。</span></span></p>');
INSERT INTO content
                    VALUES (249, '<p style="text-indent: 30pt; text-align: justify;"><span style="font-family: 微软雅黑;">10月8日上午，我校在行政楼一楼会议室召开了2024-2025学年第一学期第二次教学工作例会。教务处、质量监测与评估中心负责人、各教学院（部）院长（主任），教学副院长（副主任），教务科长等相关负责人参加了会议，副校长傅志军主持会议并讲话。</span></p><p style="text-indent: 30pt; text-align: center;"><img src="file:///C:\Users\Administrator\AppData\Local\Temp\ksohtml7996\wps1.png" alt="" data-href="" style=""><span style="font-family: 微软雅黑;"> </span><img src="/data/upload/editor/1750835036519.png" alt="1750835036519.png" data-href="/data/upload/editor/1750835036519.png" style="width: 558.00px;height: 375.19px;"></p><p style="text-indent: 30pt; text-align: justify;"><span style="font-family: 微软雅黑;">会上，教务处对9月份工作进行了总结，并布置了10月份工作：1.落实好毕业生岗位实习工作，对集中实习和自主实习做好摸底；2.做好毕业生毕业论文（设计）工作，把好“选题关”、“过程关”、“质量关”；3.对标对表按时完成本科教学合格评估自查工作报送材料；4.做好2025年新设本科申报工作和本科专业建设发展规划工作；5.做好高等教育质量监测国家数据平台填报工作。</span></p><p style="text-indent: 30pt; text-align: justify;"><span style="font-family: 微软雅黑;">副校长傅志军在会上对教学管理工作提出要求：一是要加强学习，提高能力。他强调，全体教学管理人员及教师应不断提升自我，通过持续学习增强专业素养。在日常工作中，要注重培养发现问题和解决问题的能力，确保教学工作的高效运行。</span></p><p style="text-indent: 30pt; text-align: justify;"><span style="font-family: 微软雅黑;">二是要转变观念，求真务实。必须紧跟时代步伐，转变观念，摒弃形式主义，要认真扎实地做好每一项工作，坚持实事求是，确保教学质量和教学管理的实效性。</span></p><p style="text-indent: 30pt; text-align: justify;"><span style="font-family: 微软雅黑;">三是具体工作安排。1.做好2025年新设本科申报工作和本科专业建设发展规划工作。各学院需积极准备，严格按照教育部及学校的相关规定和要求开展相关工作；2.做好期中教学检查工作。教务处要组织好期中教学检查，各教学院（部）需提前做好自查工作，并针对检查中发现的问题及时整改；3.通报11月份教学活动月安排。为促进教师间的交流与合作，提升教师教学水平，学校将于11月份举办教学活动月，活动内容包括教师公开课、青年教师沙龙和师生座谈会等。</span></p>');
INSERT INTO content
                    VALUES (250, '<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">1</span><span style="font-size: 16pt;">1</span><span style="font-size: 16pt;">月</span><span style="font-size: 16pt;">2</span><span style="font-size: 16pt;">5日</span><span style="font-size: 16pt;">下</span><span style="font-size: 16pt;">午，</span><span style="font-size: 16pt;">我校</span><span style="font-size: 16pt;">在行政楼</span><span style="font-size: 16pt;">一</span><span style="font-size: 16pt;">楼会议室召开了2025年拟招生专业设置工作会议</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">旨在进一步优化学校专业结构，</span><span style="color: #000000; font-size: 16pt;">提升主干专业、重点发展专业服务产业适配度。</span><span style="font-size: 16pt;">教务处、质量监测与评估中心、人事处、招就处、职培中心、实验实训管理中心、资产管理中心、校企合作办负责人，各学院教学副院长</span><span style="font-size: 16pt;">、</span><span style="font-size: 16pt;">教务科长等相关负责人</span><span style="font-size: 16pt;">参加了会议</span><span style="font-size: 16pt;">，</span><span style="font-size: 16pt;">副校长傅志军主持会议并讲话。</span></span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;"><img style="display: block; margin-left: auto; margin-right: auto;" src="http://jwc.jxuspt.edu.cn/resource_znkj/20241216/675fcccfb760ba23a2900ae7.png" /></span></span></p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify">&nbsp;</p>
<p style="margin-bottom: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; font-family: Tahoma; font-size: 11pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">会议伊始，教务处</span><span style="font-size: 16pt;">处长李嵩</span><span style="font-size: 16pt;">对江西省教育厅办公室下发的《关于做好江西省2025年职业教育拟招生专业设置管理工作的通知》</span><span style="font-size: 16pt;">进行了详细解读，</span><span style="font-size: 16pt;">说明了各项附件的填写方法和注意事项，</span><span style="font-size: 16pt;">明确了下一步的工作要求和时间节点。与会人员围绕拟招生专业设置的具体问题进行了深入讨论，并提出了许多建设性意见和建议</span><span style="font-size: 16pt;">。</span></span></p>
<p style="margin-right: 0pt; text-indent: 32pt; text-align: justify; line-height: 1.5; margin-bottom: 10pt; margin-left: 6pt; font-family: 仿宋; font-size: 15pt;" align="justify"><span style="font-family: 仿宋;"><span style="font-size: 16pt;">副校长傅志军在会上对几项重点工作进行提示，一是加强2025届毕业学生实习安全和毕业设计（论文）管理工作。加强实习过程的安全监管，保障学生人身及财产安全，毕业生辅导员、论文指导教师要加强与学生的联系，加强过程管理和质量监控，实时跟进学生论文进度。</span><span style="font-size: 16pt;">二是认真准备2025年拟申报的本、专科专业评审会</span><span style="font-size: 16pt;">。要早做准备，</span><span style="font-size: 16pt;">积极听取专家建议</span><span style="font-size: 16pt;">。</span><span style="font-size: 16pt;">三是</span><span style="font-size: 16pt;">进一步规范期末考试试卷命题工作</span><span style="font-size: 16pt;">。四是</span><span style="font-size: 16pt;">高度重视拟招生专业设置工作</span><span style="font-size: 16pt;">。各学院要</span><span style="color: #000000; font-size: 16pt;">充分认识</span><span style="color: #000000; font-size: 16pt;">到</span><span style="color: #000000; font-size: 16pt;">专业设置工作的重要性，严格按照规定程序、时间和标准完成</span><span style="color: #000000; font-size: 16pt;">提交</span><span style="color: #000000; font-size: 16pt;">工作</span><span style="color: #000000; font-size: 16pt;">。要</span><span style="font-size: 16pt;">紧紧围绕国家及区域建设现代化产业体系的需求，结合学校未来的建设发展规划，对照教育部职业教育标准，科学合理地调整专业设置。</span></span></p>');
INSERT INTO content
                    VALUES (251, '<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">近日，2024年江西省教学成果奖青年培育项目评选结果</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">公布</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">，我校网络工程学院申报的《党建引领、产教协同，职业本科网络类专业</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">&ldquo;四对接&ldquo;人才培养创新与实践</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">》和VR与艺术学院申报的《&ldquo;一体设计、双向迭代、三线贯通&rdquo;环境艺</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">术设计专业课程教学改革创新与实践</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">》两个项目成功入选</span>。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify">&nbsp;</p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2051454705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=eE1HCQDIELW25gN4bf0hQPpYPNo%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 427px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A45%E5%9B%BE%E7%89%871.png?Expires=2051454705&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=eE1HCQDIELW25gN4bf0hQPpYPNo%3D" alt="" width="650" height="427" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><a style="box-sizing: border-box; color: #337ab7; text-decoration-line: none; margin: 0px; padding: 0px; border-width: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; list-style-type: none; vertical-align: baseline; transition: 0.3s ease-in;" href="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A58%E5%9B%BE%E7%89%872.png?Expires=2051454718&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=OPhzbZiBMnr2Jq2kln5mxsORpjM%3D" data-fancybox="gallery"><img class="imgstyle" style="box-sizing: border-box; border-width: 0px; vertical-align: baseline; margin: 0px auto; padding: 0px; font-size: 16px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; filter: saturate(1.1); display: block; height: 298px;" src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-01-06%2000%3A31%3A58%E5%9B%BE%E7%89%872.png?Expires=2051454718&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=OPhzbZiBMnr2Jq2kln5mxsORpjM%3D" alt="" width="650" height="298" /></a></span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: justify; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;" align="justify"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000;">据悉，本次申报项目经省教育厅组织专家评审、会议研究，拟立项江西省教学成果奖青年培育项目（职业教育类项目）167项。</span></p>
<p style="box-sizing: border-box; margin: 0pt 0pt 0.0001pt; padding: 0px; border-width: 0px; font-size: 10.5pt; font-family: Calibri; text-decoration-line: none; list-style-type: none; vertical-align: baseline; line-height: 2; text-align: left; color: #333333; white-space: normal; background-color: #ffffff; text-indent: 2em;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-size: 14px; font-family: 微软雅黑; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: black;"><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">此次入选充分展现了近年来我校在推进教育教学改革、优化专业建设以及创新人才培养模式等方面所取得的阶段性成果。</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">这</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">不仅是对</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">我</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">校教育教学改革成果的肯定，</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">也</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">是对青年教师团队辛勤付出的认可。学校将进一步加大对青年教师的培养和支持力度，不断加大教育教学研究和改革力度，推动学校教育教学水平再上新台阶</span><span style="box-sizing: border-box; margin: 0px; padding: 0px; border-width: 0px; font-family: \'Microsoft YaHei\'; text-decoration-line: none; list-style-type: none; vertical-align: baseline; color: #000000; font-size: 16px;">。</span></span></p>');
INSERT INTO content
                    VALUES (252, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="color: rgb(51, 51, 51); font-family: 微软雅黑;">3月7日，我校在行政楼一楼会议室召开了2024-2025学年第二学期第二次教学工作例会。会议由副校长傅志军主持，教务处、质量监测与评估中心负责人及部门相关人员，各教学院（部）院长（主任）、教学副院长（副主任）、教务科长等相关负责人参加了会议。</span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"><img src="/data/upload/editor/1750836133934.png" alt="1750836133934.png" data-href="/data/upload/editor/1750836133934.png" style="width: 874.00px;height: 554.81px;"></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="color: rgb(51, 51, 51); font-family: 微软雅黑;">会议听取了校督导组组长黄承烈对开学以来教学督查情况的汇报。从督查情况来看，整体教学情况正常，但仍存在一些问题，需进一步改进。评建办主任何习平随后布置了本学期实践教学专项检查工作，详细说明了检查目标、内容及具体要求，强调需通过专项检查强化实践教学质量，突出专业特色。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="color: rgb(51, 51, 51); font-family: 微软雅黑;">教务处副处长王金林对近期的教学与管理工作进行了布置安排。针对2025届本科生毕业论文（设计）及岗位实习，要求各学院严格把控进度与质量；同步推进第二批“十四五”职业教育国家规划教材申报工作，确保我校推荐的教材按时完成系统填报。课程思政示范课程申报工作须于3月28日前完成，各学院需积极组织推荐。此外，已获学士学位授权专业需再次梳理专业建设材料，做好质量评估准备。各学院需高度重视年检迎检工作，严抓教风学风建设，加强新入职教师培训指导，并动员师生积极参与教学成果奖申报。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="color: rgb(51, 51, 51); font-family: 微软雅黑;">副校长傅志军提出了三点要求：一是解放思想、转变观念，主动适应职业教育发展新形势，不断加强自我学习和管理，提升教学管理水平。二是要求全体人员要借智、借力、借道，实干、苦干、巧干，强化实践教学，加强校企合作，共建专业课程、教材和实训基地，做好实验（训）指导书编写工作，突出专业特色。三是扎实推进具体工作，包括：要强化学风教风建设，落实学生晨读、晚自习制度，做好师生“六带”“三带”工作，严格教学监督，确保教师按时到岗、认真授课；要定期组织活动，深入研究教学方法，要动员师生积极参与各类竞赛，提升获奖数量与质量；要重点做好新增7个本科专业及2个专科专业的人才培养方案制定，统一专业基础课程模块，增设技能训练课程。</span></p>');
