INSERT INTO content
                    VALUES (259, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">5月28日，我校在IBM大楼二楼205会议室召开了本学期第四次教学工作例会。校务委员梅龙，教务处、质量监测与评估中心负责人，各教学院（部）院长（主任）、教学副院长（副主任）及教务科长等相关负责人参会。会议由校务委员傅志军主持。</span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"> <img src="/data/upload/editor/1750833916439.png" alt="1750833916439.png" data-href="/data/upload/editor/1750833916439.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议首先听取了校督导组组长黄承烈的教学督查反馈。他表示，学校总体教学秩序良好，但部分问题还需重视，要求各教学单位切实加强教学管理，提升教师教学能力，确保教学质量稳步提升。随后，马克思主义学院院长助理汪玲分享了学院在考试工作中的具体做法、注意事项和经验，为各学院（部）提供了有益的参考和借鉴。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">教务处就近期教学质量工程项目、岗位实习工作、毕业设计（论文）指导工作、教学运行相关工作、考试相关工作、学位评定、毕业证书及学位证书办理等多项重点工作进行部署。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">傅志军在总结讲话中重点强调三点：一是进一步提升毕业论文（设计）规范性，合理调整2026届毕业论文与实习时间。二是严谨做好期末试卷命题、阅卷与评卷工作，确保考试公平公正。三是按本科合格评估指标释义要求，积极引进行业、企业导师，优化理论课与实训课的排课管理，以提升教学质量和水平。</span></p>');
INSERT INTO content
                    VALUES (260, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月5日上午，由教务处牵头在IBM大楼三楼会议室召开了评建工作第二专项组第一次工作会议。发展规划处、招生就业处、职培中心、科技处、团委、学工处、实验实训中心、人事处、教师发展中心、校企合作办、信息中心、教务处及评建办等相关部门负责人参加了会议。本次会议旨在扎实推进评建工作第二专项组任务，明确分工，协调解决相关问题。会议由教务处副处长罗磊主持，校务委员傅志军出席会议并讲话。</span></p><p style="text-align: center; line-height: 2;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-16%2010%3A15%3A02image.png?Expires=2065400102&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=rHZ%2FqWDm0PjIx6cLYUgaE%2Fns%2FQc%3D" alt="" data-href="" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议上，教务处副处长王金林带领与会人员共同学习了教育部《本科层次职业学校本科教学工作合格评估指标释义(试行)》（教督局函〔2025〕13号）文件中关于专业建设、课程建设与教材建设的关键指标，并对各项指标的内涵进行了详细解读。随后，罗磊具体介绍了第二专项组——教学建设（专业、课程与教材建设）的详细任务清单。与会各部门负责人围绕任务清单中的各条款进行了深入讨论，进一步厘清了工作职责，明确了任务的具体分工，确保责任落实到部门。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">傅志军对第二专项组下一阶段工作提出了明确要求。他强调，一是要继续深入学习合格评估指标释义内容，明确未来工作方向；二是要以指标释义的要求和标准去衡量和开展工作；三是要加快推进制度规范等软指标的建设，做到简明、扼要、管用，并高度重视硬指标和软指标中的硬要求；四是在理清职责的同时，要对过去的工作进行查漏补缺，找差距，并在遇到困难时及时协调和沟通，形成合力，确保评建任务高效、高质量完成。</span></p>');
INSERT INTO content
                    VALUES (261, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月11日上午，我校在行政楼101会议室召开了2024-2025学年第二学期教学工作指导会议。会议由校务委员傅志军主持，教务处全体成员以及各教学院（部）教务科长、教学秘书参加了会议。</span></p><p style="text-align: center; line-height: 2;"><img src="/data/upload/editor/1750834130666.png" alt="1750834130666.png" data-href="/data/upload/editor/1750834130666.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会上，傅志军反复强调了学习的重要性，要求教务人员务必加强学习，不仅要掌握教育教学理论，还要积极学习心理学、教育学、管理学等相关知识，不断提升自身的专业素养和工作能力。在学习的基础上，还需转变观念，抛弃陈旧的工作理念，紧跟时代发展和学校要求，特别是要严格依据本科合格评估指标释义的精神来指导和规范日常工作。工作中要力戒“交作业”式的应付心态，提倡实干、巧干，追求工作实效。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">另外，布置了几项具体工作：一是要加快收集关于2026届本科毕业生毕业论文（设计）与岗位实习工作的反馈意见，尽快完善实施方案并实施。二是扎实做好期末考试工作（包括命题、制卷、考试、阅卷、成绩登录等各项具体工作），认真做好下学期教学工作安排，进一步优化课程结构体系与内容。三是进一步完善2025届本科毕业生的毕业论文（设计），教务处要做好后续服务，印刷前要规范，确保2025届本科毕业论文（设计）抽检全部合格。四是抓紧完成7个本科（试点）专业人才培养方案编制工作，二级学院要鼓励师生参加各类竞赛，争取学生竞赛提质增量。五是切实做好新增设本科专业的申报工作，重点聚焦专业带头人遴选、团队建设以及实践教学等关键要素。</span></p>');
INSERT INTO content
                    VALUES (262, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月4日下午，我校在IBM大楼411会议室召开了2024-2025学年第二学期本科专业申报专题会议。设有本科专业的教学院长、副院长和教务处、质量监测与评估中心负责人及相关人员共同参会。会议由校务委员傅志军主持。</span></p><p style="text-align: center; line-height: 2;"><img src="/data/upload/editor/1750834235802.png" alt="1750834235802.png" data-href="/data/upload/editor/1750834235802.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议伊始，智能科技学院教学副院长蒋淦华分享了在智能制造工程技术专业申报过程中的宝贵心得。他详细阐述了专业申报材料的撰写要点，包括专业论证评审表需严格参照指导委员会文件要求，确保成员架构科学合理；招生信息表应精准对标申报指南，规范标题命名与内容表述；论证材料则需突出逻辑主线，采用图文并茂的呈现方式，开篇即总结，结尾呼应，以增强材料的说服力和可读性。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会上，傅志军带领与会人员深入学习教育部《本科层次职业学校本科教学工作合格评估指标释义(试行)》文件精神，聚焦专业带头人与团队建设等核心内容，明确提出专业申报四大关键要求。一是严格对标评估标准选拔专业带头人，确保资质符合规范。二是构建结构合理的人才培养方案编制与评审团队。三是精准定位专业服务面向，要求南昌校区专业紧密对接江西省“1269”行动计划及南昌市“8810”行动计划，井冈山校区专业须服务省“1269”行动与吉安电子信息产业、井冈山“革命摇篮”红色资源。四是申报材料必须系统回应“开设必要性”“院校开设能力”“办学条件支撑度”及“材料规范性”四大核心问题。并强调各教学院长须亲自部署、全程参与新专业申报工作，确保材料既紧扣国家政策与区域发展需求，又突出办学特色与专业优势。</span></p>');
INSERT INTO content
                    VALUES (263, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月4日下午，我校在IBM大楼411会议室召开了2024-2025学年第二学期本科专业申报专题会议。设有本科专业的教学院长、副院长和教务处、质量监测与评估中心负责人及相关人员共同参会。会议由校务委员傅志军主持。</span></p><p style="text-align: center; line-height: 2;"><img src="/data/upload/editor/1750834235802.png" alt="1750834235802.png" data-href="/data/upload/editor/1750834235802.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议伊始，智能科技学院教学副院长蒋淦华分享了在智能制造工程技术专业申报过程中的宝贵心得。他详细阐述了专业申报材料的撰写要点，包括专业论证评审表需严格参照指导委员会文件要求，确保成员架构科学合理；招生信息表应精准对标申报指南，规范标题命名与内容表述；论证材料则需突出逻辑主线，采用图文并茂的呈现方式，开篇即总结，结尾呼应，以增强材料的说服力和可读性。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会上，傅志军带领与会人员深入学习教育部《本科层次职业学校本科教学工作合格评估指标释义(试行)》文件精神，聚焦专业带头人与团队建设等核心内容，明确提出专业申报四大关键要求。一是严格对标评估标准选拔专业带头人，确保资质符合规范。二是构建结构合理的人才培养方案编制与评审团队。三是精准定位专业服务面向，要求南昌校区专业紧密对接江西省“1269”行动计划及南昌市“8810”行动计划，井冈山校区专业须服务省“1269”行动与吉安电子信息产业、井冈山“革命摇篮”红色资源。四是申报材料必须系统回应“开设必要性”“院校开设能力”“办学条件支撑度”及“材料规范性”四大核心问题。并强调各教学院长须亲自部署、全程参与新专业申报工作，确保材料既紧扣国家政策与区域发展需求，又突出办学特色与专业优势。</span></p>');
INSERT INTO content
                    VALUES (264, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月10日上午，由教务处牵头在IBM大楼三楼会议室召开了评建工作第八专项组（教学质量）第一次工作会议。专项组所涉单位均参加会议，评建办负责人列席会议。会议由教务处副处长罗磊主持，校务委员傅志军出席会议并讲话。</span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"> <img src="/data/upload/editor/1750834331764.png" alt="1750834331764.png" data-href="/data/upload/editor/1750834331764.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议伊始，罗磊带领与会人员深入学习了《本科层次职业学校本科教学工作合格评估指标释义(试行)》（教督局函〔2025〕13号）中关于教学质量的相关指标，并对各项指标的基本要求、内涵解释及考察重点进行了详细解读。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">随后，与会人员针对任务清单中的各项条款进行了细致研讨，进一步明确了各自的工作职责和任务分工，确保评建工作的各项任务能够得到有效落实。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会议最后，傅志军发表了总结讲话。他强调，全体参会人员要加强学习合格评估指标释义的内容，切实转变思想观念，以务实的态度投入工作。同时，他特别指出要高度重视释义中的硬指标，仔细研究软指标中的硬要求，确保各项工作扎实、有效地推进。此外，要求各单位在聚焦自身任务的同时，还需树立全局意识，协调开展工作，以形成合力，共同保证材料的完整性，确保学校整体评建工作高效、有序开展。</span></p><p style="text-align: justify;"> </p>');
INSERT INTO content
                    VALUES (265, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">近日，2025-2026年江西省职业院校技能大赛赛项赛事承办校和赛道牵头学校名单公布，我校成功获批承办江西省职业院校技能大赛--特色赛项--Web应用软件开发（高职组），这是对我校深耕信息技术教育、强化学生实践创新能力的高度认可，更是对学校产教融合成果的充分肯定。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"> </p><p style="text-align: center;"><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-21%2016%3A23%3A47image.png?Expires=2065854227&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=QpaJ1b7TF7KwdZCca1x0nHOa6NY%3D" alt="" data-href="" style=""><img src="https://aheadedu.oss-cn-shenzhen.aliyuncs.com/school_branch/jiiewebsite/img/2025-06-21%2016%3A23%3A3126fc0abc1e6c0010525f714997ae568.png?Expires=2065854212&amp;OSSAccessKeyId=LTAI4GEYjbEWU9Knh4iN17fd&amp;Signature=bObTFha1tLXJU5s6M0rCnXWgaLk%3D" alt="" data-href="" style=""></p><p style="text-align: justify;"> </p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">本次获批的赛项紧密对接数字经济发展需求，涵盖Web应用开发、前端技术应用、编程实践等核心模块，旨在通过高规格竞赛平台，检验学生软件开发能力、系统设计思维及团队协作水平。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">作为承办校，我校将全力以赴做好赛事筹备与组织工作，为全省职业院校搭建技术交流与技能比拼的优质舞台。我校也将以赛事为契机，深化校际合作、校企合作，推动技能标准共建、教学资源共享，构建产教融合新生态，通过“以赛促学、以赛促教、以赛促改”，全面提升学生数字化职业素养与创新能力，为江西省数字经济产业输送更多高端技能人才。</span></p>');
INSERT INTO content
                    VALUES (266, '<p style="text-indent: 2em; text-align: left; line-height: 2;"><span style="font-family: 微软雅黑;">6月16日，校党委书记、督导专员饶勇，党委副书记、执行校长范红铭带领有关部门负责人，深入各个考场，开展期末考试巡考工作。 </span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"><img src="/data/upload/editor/1750835206091.png" alt="1750835206091.png" data-href="/data/upload/editor/1750835206091.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">巡考期间，饶勇一行对考试秩序、考场设施环境、学生考试纪律、监考教师履职情况等有关工作进行了全面检查。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">从巡考情况看，期末考试组织严密，考务管理规范有序。各门课程考试顺利进行，监考教师认真负责，同学们考风严谨，态度端正，考场秩序井然。</span></p><p style="text-align: center; line-height: 2;"> <img src="/data/upload/editor/1750835257072.png" alt="1750835257072.png" data-href="/data/upload/editor/1750835257072.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">长期以来，学校高度重视学风考风建设，校领导带队进行期末巡考已成为每学期开展的一项常态工作。今后，学校将不断加强考务管理，完善考务细节，进一步强化学生诚信考试教育，以考风促进教风、学风建设，把责任落实落细，营造考风端正、考纪严明的良好氛围，切实提高人才培养质量。</span></p>');
INSERT INTO content
                    VALUES (267, '<p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">6月20日，我校在学术报告厅隆重举行2025年考研表彰暨考研动员大会。</span></p><p style="text-align: center;"><img src="/data/upload/editor/1750835352098.png" alt="1750835352098.png" data-href="/data/upload/editor/1750835352098.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">校领导范红铭、徐国荣、高建国、梅龙、张永革、郭宏、吴志勇等出席会议，傅志军主持会议。</span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"><img src="/data/upload/editor/1750835369916.png" alt="1750835369916.png" data-href="/data/upload/editor/1750835369916.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">范红铭代表学校向考取研究生的同学表示热烈的祝贺！向精心施教、助力学生成功的老师表示诚挚的谢意！他指出，考研，作为高等教育的重要一环，对于个人和社会的发展都具有不可忽视的重要性。学校高度重视考研工作，将其视为提高人才培养质量、推动学校内涵式发展的重要抓手，不断优化考研服务体系，加强考研指导，集中教学资源和有关力量创造良好的考研学习和生活条件。他向正在准备考研的同学提出了建议和希望：一要明确目标，尽早规划；二要制定计划，科学备考；三要树立信心，贵在坚持；四要营造氛围，互促共进。</span></p><p style="text-align: center; line-height: 2;"><img src="/data/upload/editor/1750835392358.png" alt="1750835392358.png" data-href="/data/upload/editor/1750835392358.png" style=""></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">今年，我校学子考研再创佳绩，87名同学分别被长安大学、宁夏大学、江西财经大学、江西师范大学、江西农业大学、华南农业大学、燕山大学、景德镇陶瓷大学等多所国内知名高校以及昆士兰大学、约克大学等国外高校录取。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">会上，高建国宣读了学校关于表彰2025年考取硕士研究生学生的决定。</span></p><p style="text-align: center;"><img src="/data/upload/editor/1750835407578.png" alt="1750835407578.png" data-href="/data/upload/editor/1750835407578.png" style="width: 585.00px;height: 390.31px;"></p><p style="text-align: center;"><img src="/data/upload/editor/1750835435251.png" alt="1750835435251.png" data-href="/data/upload/editor/1750835435251.png" style="width: 594.00px;height: 356.80px;"></p><p style="text-align: center;"><img src="/data/upload/editor/1750835514255.png" alt="1750835514255.png" data-href="/data/upload/editor/1750835514255.png" style="width: 592.00px;height: 197.30px;"><span style="font-family: 微软雅黑;"><br></span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">校领导为成功考取硕士研究生的同学颁发荣誉证书及专项奖学金，向他们表示祝贺并勉励其继续奋进。同时，校领导对在考研组织工作中表现突出的学院进行嘉奖。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">来自VR与艺术学院的2025届毕业生段伟明作为考研代表发言。已成功考取长安大学研究生的他，分享了自己的备考经验和心路历程，鼓励学弟学妹们坚定信心、锁定目标、永不言弃。</span></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">新媒体学院2022级本科学生代表王浩楠在发言中表示，将以优秀学长学姐为榜样，在考研征途中全力以赴、奋勇前行，表达了对未来考研的决心与信心。</span></p><p style="text-indent: 2em; text-align: center; line-height: 2;"><img src="/data/upload/editor/1750835553711.png" alt="1750835553711.png" data-href="/data/upload/editor/1750835553711.png" style="width: 597.00px;height: 283.45px;"></p><p style="text-indent: 2em; text-align: justify; line-height: 2;"><span style="font-family: 微软雅黑;">各学院（部）院长（主任），教务处、学工处、团委等部门负责人，2025年考取研究生的同学，2022级准备考研的同学参加大会。</span></p>');
